  meeting: { bg: 'rgba(99,102,241,0.08)', border: '#6366f1', label: '회의', labelColor: 'benefit' },
  personal: { bg: 'rgba(16,185,129,0.08)', border: '#10b981', label: '개인', labelColor: 'gray' },
