/* --------------------------------------------------------------------------
   Video Player (Arco Design + Mantine 벤치마크)
   재생/일시정지, 볼륨, 진행 바, 챕터, 재생 목록이 있는 미디어 플레이어 UI
-------------------------------------------------------------------------- */
const VIDEO_CHAPTERS = [
  { id: 'ch1', title: '디자인 시스템 소개', start: 0, duration: 65 },
  { id: 'ch2', title: 'Eclipse 테마 구조', start: 65, duration: 90 },
  { id: 'ch3', title: '3-tier 토큰 시스템', start: 155, duration: 110 },
  { id: 'ch4', title: 'Storybook 연동', start: 265, duration: 85 },
  { id: 'ch5', title: '배포 및 버저닝', start: 350, duration: 70 },
]
const VIDEO_TOTAL = 420

const PLAYLIST_VIDEOS = [
  { id: 'v1', title: 'Orbit UI 완전 정복 1편', author: 'Design Team', views: 4820, active: true },
  { id: 'v2', title: 'vanilla-extract 심화 스타일링', author: 'Core Team', views: 3210, active: false },
  { id: 'v3', title: '접근성 컴포넌트 패턴', author: 'A11y Squad', views: 2180, active: false },
]

function formatTime(sec: number): string {
  const m = Math.floor(sec / 60)
  const s = sec % 60
  return `${m}:${s.toString().padStart(2, '0')}`
}

const VideoPlayerRender = () => {
  const [playing, setPlaying] = useState(false)
  const [position, setPosition] = useState(0)
  const [volume, setVolume] = useState(80)
  const [muted, setMuted] = useState(false)
  const [quality, setQuality] = useState('1080p')

  const currentChapter = VIDEO_CHAPTERS.findLast((ch) => position >= ch.start) ?? VIDEO_CHAPTERS[0]
  const progressPct = Math.round((position / VIDEO_TOTAL) * 100)

  return (
    <div style={{ maxWidth: 860, fontFamily: 'system-ui, sans-serif', background: '#0f172a', borderRadius: 16, overflow: 'hidden' }}>
      {/* 비디오 영역 */}
      <div
        style={{ position: 'relative', aspectRatio: '16/9', background: 'linear-gradient(135deg, #1e293b 0%, #0f172a 100%)', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
        onClick={() => setPlaying((p) => !p)}
      >
        <div style={{ textAlign: 'center' }}>
          <div style={{ width: 64, height: 64, borderRadius: '50%', background: playing ? 'rgba(99,102,241,0.9)' : 'rgba(255,255,255,0.15)', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 12px', transition: 'background 0.2s' }}>
            <span style={{ fontSize: 28, color: '#fff' }}>{playing ? '⏸' : '▶'}</span>
          </div>
          <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.6)' }}>{playing ? '재생 중' : '클릭하여 재생'}</div>
        </div>

        {/* 챕터 레이블 */}
        <div style={{ position: 'absolute', top: 12, left: 12, padding: '4px 10px', borderRadius: 6, background: 'rgba(99,102,241,0.85)', fontSize: 11, fontWeight: 700, color: '#fff' }}>
          {currentChapter.title}
        </div>

        {/* 화질 */}
        <div style={{ position: 'absolute', top: 12, right: 12, padding: '4px 10px', borderRadius: 6, background: 'rgba(0,0,0,0.6)', fontSize: 11, fontWeight: 600, color: '#fff', cursor: 'default' }}>
          {quality}
        </div>
      </div>

      {/* 컨트롤 바 */}
      <div style={{ padding: '12px 20px 8px', background: '#1e293b' }}>
        {/* 진행 바 */}
        <div
          style={{ height: 4, background: '#334155', borderRadius: 2, marginBottom: 12, cursor: 'pointer', position: 'relative' }}
          onClick={(e: React.MouseEvent<HTMLDivElement>) => {
            const rect = (e.currentTarget as HTMLDivElement).getBoundingClientRect()
            const pct = (e.clientX - rect.left) / rect.width
            setPosition(Math.round(pct * VIDEO_TOTAL))
          }}
        >
          {/* 챕터 마커 */}
          {VIDEO_CHAPTERS.slice(1).map((ch) => (
            <div key={ch.id} style={{ position: 'absolute', top: -2, left: `${(ch.start / VIDEO_TOTAL) * 100}%`, width: 2, height: 8, background: '#64748b', borderRadius: 1 }} />
          ))}
          <div style={{ height: '100%', width: `${progressPct}%`, background: '#6366f1', borderRadius: 2, position: 'relative' }}>
            <div style={{ position: 'absolute', right: -6, top: -4, width: 12, height: 12, borderRadius: '50%', background: '#6366f1', border: '2px solid #fff' }} />
          </div>
        </div>

        {/* 컨트롤 버튼 행 */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <button
            onClick={() => setPlaying((p) => !p)}
            style={{ background: 'none', border: 'none', color: '#fff', fontSize: 18, cursor: 'pointer', padding: 0, lineHeight: 1 }}
          >
            {playing ? '⏸' : '▶'}
          </button>

          <button
            onClick={() => setPosition((p) => Math.max(0, p - 15))}
            style={{ background: 'none', border: 'none', color: '#94a3b8', fontSize: 14, cursor: 'pointer', padding: 0 }}
          >
            ⏮ 15s
          </button>

          <button
            onClick={() => setPosition((p) => Math.min(VIDEO_TOTAL, p + 15))}
            style={{ background: 'none', border: 'none', color: '#94a3b8', fontSize: 14, cursor: 'pointer', padding: 0 }}
          >
            15s ⏭
          </button>

          <div style={{ display: 'flex', alignItems: 'center', gap: 6, flex: 1 }}>
            <button
              onClick={() => setMuted((m) => !m)}
              style={{ background: 'none', border: 'none', color: '#94a3b8', fontSize: 14, cursor: 'pointer', padding: 0 }}
            >
              {muted ? '🔇' : '🔊'}
            </button>
            <input
              type="range"
              min={0}
              max={100}
              value={muted ? 0 : volume}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => { setVolume(Number(e.target.value)); setMuted(false) }}
              style={{ width: 80, accentColor: '#6366f1' }}
            />
          </div>

          <span style={{ fontSize: 12, color: '#94a3b8', fontVariantNumeric: 'tabular-nums', whiteSpace: 'nowrap' }}>
            {formatTime(position)} / {formatTime(VIDEO_TOTAL)}
          </span>

          <div style={{ display: 'flex', gap: 6 }}>
            {['720p', '1080p', '4K'].map((q) => (
              <button
                key={q}
                onClick={() => setQuality(q)}
                style={{ padding: '2px 8px', borderRadius: 4, border: `1px solid ${quality === q ? '#6366f1' : '#334155'}`, background: quality === q ? '#6366f1' : 'transparent', color: quality === q ? '#fff' : '#94a3b8', fontSize: 11, cursor: 'pointer' }}
              >
                {q}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* 하단: 챕터 + 재생목록 */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 280px', background: '#0f172a' }}>
        {/* 챕터 목록 */}
        <div style={{ padding: '16px 20px', borderRight: '1px solid #1e293b' }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: '#475569', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 12 }}>챕터</div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
            {VIDEO_CHAPTERS.map((ch) => {
              const isActive = currentChapter.id === ch.id
              return (
                <div
                  key={ch.id}
                  style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '8px 10px', borderRadius: 8, background: isActive ? '#1e293b' : 'transparent', cursor: 'pointer', transition: 'background 0.15s' }}
                  onClick={() => setPosition(ch.start)}
                >
                  <div style={{ width: 6, height: 6, borderRadius: '50%', background: isActive ? '#6366f1' : '#334155', flexShrink: 0 }} />
                  <div style={{ flex: 1, fontSize: 13, color: isActive ? '#fff' : '#94a3b8', fontWeight: isActive ? 600 : 400 }}>
                    {ch.title}
                  </div>
                  <div style={{ fontSize: 11, color: '#475569', fontVariantNumeric: 'tabular-nums' }}>
                    {formatTime(ch.duration)}
                  </div>
                </div>
              )
            })}
          </div>

          {/* PageDots 챕터 인디케이터 */}
          <div style={{ display: 'flex', gap: 6, marginTop: 14, paddingTop: 14, borderTop: '1px solid #1e293b', justifyContent: 'center' }}>
            {VIDEO_CHAPTERS.map((ch) => (
              <PageDots
                key={ch.id}
                selected={currentChapter.id === ch.id}
                onClick={() => setPosition(ch.start)}
              />
            ))}
          </div>
        </div>

        {/* 재생 목록 */}
        <div style={{ padding: '16px 16px' }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: '#475569', textTransform: 'uppercase', letterSpacing: '0.07em', marginBottom: 12 }}>재생목록</div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {PLAYLIST_VIDEOS.map((video) => (
              <div
                key={video.id}
                style={{ display: 'flex', gap: 10, padding: '8px 10px', borderRadius: 8, background: video.active ? '#1e293b' : 'transparent', cursor: 'pointer' }}
              >
                <div style={{ width: 48, height: 36, borderRadius: 6, background: video.active ? '#6366f1' : '#1e293b', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, fontSize: 16 }}>
                  {video.active ? '▶' : '⏸'}
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 12, color: video.active ? '#fff' : '#94a3b8', fontWeight: video.active ? 600 : 400, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {video.title}
                  </div>
                  <div style={{ fontSize: 10, color: '#475569', marginTop: 2 }}>
                    {video.author} · {video.views.toLocaleString('ko-KR')}회
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  )
}

export const VideoPlayer: Story = {
  name: 'Video Player (Arco Design + Mantine 벤치마크)',
  render: () => <VideoPlayerRender />,
}

/* --------------------------------------------------------------------------
   Subscription Page (Tailwind UI + Chakra UI 벤치마크)
   플랜 비교 + 결제 폼 + 특징 체크리스트가 통합된 구독 페이지
-------------------------------------------------------------------------- */
const SUBSCRIPTION_PLANS = [
  {
    id: 'starter',
    name: 'Starter',
    monthly: 0,
    annual: 0,
    color: '#64748b',
    accentBg: '#f8fafc',
    description: '개인 프로젝트와 학습용',
    features: [
      { label: '컴포넌트 50개+', included: true },
      { label: 'Storybook 문서', included: true },
      { label: '커뮤니티 지원', included: true },
      { label: '피그마 키트', included: false },
      { label: '우선 지원', included: false },
      { label: '테마 빌더', included: false },
    ],
  },
  {
    id: 'pro',
    name: 'Pro',
    monthly: 29000,
    annual: 23000,
    color: '#6366f1',
    accentBg: '#eef2ff',
    description: '전문 개발자와 소규모 팀',
    badge: '인기',
    features: [
      { label: '컴포넌트 200개+', included: true },
      { label: 'Storybook 문서', included: true },
      { label: '이메일 지원', included: true },
      { label: '피그마 키트', included: true },
      { label: '우선 지원', included: true },
      { label: '테마 빌더', included: false },
    ],
  },
  {
    id: 'enterprise',
    name: 'Enterprise',
    monthly: 89000,
    annual: 71000,
    color: '#0ea5e9',
    accentBg: '#f0f9ff',
    description: '대규모 팀과 엔터프라이즈',
    features: [
      { label: '컴포넌트 무제한', included: true },
      { label: 'Storybook 문서', included: true },
      { label: '전용 슬랙 채널', included: true },
      { label: '피그마 키트', included: true },
      { label: '우선 지원 + SLA', included: true },
      { label: '테마 빌더', included: true },
    ],
  },
]

const SubscriptionPageRender = () => {
  const [billing, setBilling] = useState<'monthly' | 'annual'>('annual')
  const [selectedPlan, setSelectedPlan] = useState('pro')
  const [step, setStep] = useState<'plan' | 'payment'>('plan')
  const [agreed, setAgreed] = useState(false)

  const plan = SUBSCRIPTION_PLANS.find((p) => p.id === selectedPlan) ?? SUBSCRIPTION_PLANS[1]
  const price = billing === 'annual' ? plan.annual : plan.monthly

  return (
    <div style={{ maxWidth: 960, fontFamily: 'system-ui, sans-serif', padding: '0 16px' }}>
      {/* 헤더 */}
      <div style={{ textAlign: 'center', marginBottom: 40 }}>
        <div style={{ display: 'inline-flex', alignItems: 'center', gap: 8, background: '#eef2ff', padding: '4px 14px', borderRadius: 99, marginBottom: 12 }}>
          <div style={{ width: 6, height: 6, borderRadius: '50%', background: '#6366f1' }} />
          <span style={{ fontSize: 12, fontWeight: 700, color: '#6366f1' }}>Orbit UI 구독</span>
        </div>
        <div style={{ fontSize: 32, fontWeight: 900, color: '#0f172a', letterSpacing: '-0.03em', marginBottom: 8 }}>
          올바른 플랜을 선택하세요
        </div>
        <div style={{ fontSize: 15, color: '#64748b', marginBottom: 24 }}>
          언제든지 업그레이드하거나 취소할 수 있습니다.
        </div>

        {/* 빌링 토글 */}
        <div style={{ display: 'inline-flex', background: '#f1f5f9', borderRadius: 10, padding: 4, gap: 2 }}>
          {(['monthly', 'annual'] as const).map((b) => (
            <button
              key={b}
              onClick={() => setBilling(b)}
              style={{
                padding: '6px 16px', borderRadius: 7, fontSize: 13, fontWeight: 600, cursor: 'pointer',
                border: 'none',
                background: billing === b ? '#fff' : 'transparent',
                color: billing === b ? '#0f172a' : '#64748b',
                boxShadow: billing === b ? '0 1px 4px rgba(0,0,0,0.08)' : 'none',
                transition: 'all 0.15s',
              }}
            >
              {b === 'monthly' ? '월간' : '연간'}
              {b === 'annual' && (
                <span style={{ marginLeft: 6, fontSize: 10, fontWeight: 700, color: '#10b981', background: '#dcfce7', padding: '1px 6px', borderRadius: 99 }}>
                  -20%
                </span>
              )}
            </button>
          ))}
        </div>
      </div>

      {step === 'plan' ? (
        <>
          {/* 플랜 카드 그리드 */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16, marginBottom: 32 }}>
            {SUBSCRIPTION_PLANS.map((p) => {
              const isSelected = selectedPlan === p.id
              const displayPrice = billing === 'annual' ? p.annual : p.monthly
              return (
                <div
                  key={p.id}
                  onClick={() => setSelectedPlan(p.id)}
                  style={{
                    borderRadius: 16,
                    border: `2px solid ${isSelected ? p.color : '#e2e8f0'}`,
                    background: isSelected ? p.accentBg : '#fff',
                    padding: 24,
                    cursor: 'pointer',
                    transition: 'all 0.15s',
                    position: 'relative',
                  }}
                >
                  {p.badge && (
                    <div style={{ position: 'absolute', top: -10, left: '50%', transform: 'translateX(-50%)', background: p.color, color: '#fff', fontSize: 10, fontWeight: 800, padding: '3px 12px', borderRadius: 99 }}>
                      {p.badge}
                    </div>
                  )}

                  <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 16 }}>
                    <div>
                      <div style={{ fontSize: 16, fontWeight: 800, color: isSelected ? p.color : '#0f172a', marginBottom: 4 }}>
                        {p.name}
                      </div>
                      <div style={{ fontSize: 12, color: '#64748b' }}>{p.description}</div>
                    </div>
                    <div style={{
                      width: 20, height: 20, borderRadius: '50%',
                      border: `2px solid ${isSelected ? p.color : '#d1d5db'}`,
                      background: isSelected ? p.color : 'transparent',
                      display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0,
                    }}>
                      {isSelected && <div style={{ width: 7, height: 7, borderRadius: '50%', background: '#fff' }} />}
                    </div>
                  </div>

                  <div style={{ marginBottom: 20 }}>
                    <span style={{ fontSize: 28, fontWeight: 900, color: '#0f172a' }}>
                      {displayPrice === 0 ? '무료' : `₩${displayPrice.toLocaleString('ko-KR')}`}
                    </span>
                    {displayPrice > 0 && <span style={{ fontSize: 13, color: '#94a3b8', marginLeft: 4 }}>/월</span>}
                  </div>

                  <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                    {p.features.map((feat) => (
                      <div key={feat.label} style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                        <div style={{
                          width: 16, height: 16, borderRadius: '50%', flexShrink: 0,
                          background: feat.included ? `${p.color}20` : '#f1f5f9',
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                        }}>
                          <span style={{ fontSize: 9, color: feat.included ? p.color : '#cbd5e1' }}>
                            {feat.included ? '✓' : '×'}
                          </span>
                        </div>
                        <span style={{ fontSize: 12, color: feat.included ? '#374151' : '#94a3b8', textDecoration: feat.included ? 'none' : 'line-through' }}>
                          {feat.label}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              )
            })}
          </div>

          <div style={{ display: 'flex', justifyContent: 'center' }}>
            <SolidButton
              color="primary"
              size="large"
              onClick={() => plan.id !== 'starter' && setStep('payment')}
              style={{ minWidth: 240 }}
            >
              <SolidButton.Center>
                {plan.id === 'starter' ? '무료로 시작하기' : `${plan.name} 플랜 시작하기`}
              </SolidButton.Center>
            </SolidButton>
          </div>
        </>
      ) : (
        /* 결제 폼 */
        <div style={{ maxWidth: 520, margin: '0 auto' }}>
          <button
            onClick={() => setStep('plan')}
            style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 13, color: '#6366f1', background: 'none', border: 'none', cursor: 'pointer', marginBottom: 24, padding: 0, fontWeight: 600 }}
          >
            ← 플랜 선택으로 돌아가기
          </button>

          <div style={{ background: plan.accentBg, border: `1.5px solid ${plan.color}30`, borderRadius: 14, padding: '16px 20px', marginBottom: 28, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
              <div style={{ fontSize: 14, fontWeight: 700, color: plan.color }}>{plan.name} 플랜</div>
              <div style={{ fontSize: 12, color: '#64748b' }}>{billing === 'annual' ? '연간 결제 (-20%)' : '월간 결제'}</div>
            </div>
            <div style={{ fontSize: 20, fontWeight: 900, color: '#0f172a' }}>
              ₩{price.toLocaleString('ko-KR')}<span style={{ fontSize: 12, fontWeight: 400, color: '#94a3b8' }}>/월</span>
            </div>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: 16, marginBottom: 24 }}>
            {[
              { label: '카드 번호', placeholder: '0000 0000 0000 0000', type: 'text' },
              { label: '카드 소유자명', placeholder: '홍길동', type: 'text' },
            ].map(({ label, placeholder, type }) => (
              <div key={label}>
                <label style={{ fontSize: 12, fontWeight: 700, color: '#374151', display: 'block', marginBottom: 6 }}>{label}</label>
                <input
                  type={type}
                  placeholder={placeholder}
                  style={{ width: '100%', padding: '10px 12px', borderRadius: 10, border: '1.5px solid #e2e8f0', fontSize: 14, outline: 'none', boxSizing: 'border-box' }}
                />
              </div>
            ))}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
              {[
                { label: '유효기간', placeholder: 'MM / YY' },
                { label: 'CVC', placeholder: '000' },
              ].map(({ label, placeholder }) => (
                <div key={label}>
                  <label style={{ fontSize: 12, fontWeight: 700, color: '#374151', display: 'block', marginBottom: 6 }}>{label}</label>
                  <input
                    placeholder={placeholder}
                    style={{ width: '100%', padding: '10px 12px', borderRadius: 10, border: '1.5px solid #e2e8f0', fontSize: 14, outline: 'none', boxSizing: 'border-box' }}
                  />
                </div>
              ))}
            </div>
          </div>

          <div style={{ display: 'flex', alignItems: 'flex-start', gap: 10, marginBottom: 24, padding: '12px 14px', borderRadius: 10, background: '#f8fafc', border: '1px solid #e2e8f0' }}>
            <Switch
              checked={agreed}
              onCheckedChange={setAgreed}
            />
            <div style={{ fontSize: 12, color: '#64748b', lineHeight: 1.6 }}>
              <span style={{ fontWeight: 600, color: '#374151' }}>이용약관</span> 및{' '}
              <span style={{ fontWeight: 600, color: '#374151' }}>개인정보 처리방침</span>에 동의하며,
              구독이 자동 갱신된다는 것을 이해합니다.
            </div>
          </div>

          <SolidButton
            color="primary"
            size="large"
            style={{ width: '100%' }}
            disabled={!agreed}
          >
            <SolidButton.Center>
              {agreed ? `₩${price.toLocaleString('ko-KR')}/월 결제하기` : '약관 동의 후 결제 가능'}
            </SolidButton.Center>
          </SolidButton>

          <div style={{ display: 'flex', justifyContent: 'center', gap: 16, marginTop: 16 }}>
            {['SSL 암호화', '언제든 취소 가능', '환불 보장'].map((item) => (
              <div key={item} style={{ display: 'flex', alignItems: 'center', gap: 4, fontSize: 11, color: '#94a3b8' }}>
                <span style={{ color: '#10b981' }}>✓</span>
                {item}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  )
}

export const SubscriptionPage: Story = {
  name: 'Subscription Page (Tailwind UI + Chakra UI 벤치마크)',
  render: () => <SubscriptionPageRender />,
}

/* --------------------------------------------------------------------------
   Job Board (MUI + Raycast 벤치마크)
   채용공고 목록 + 상세 패널 + 지원 플로우가 통합된 구직 플랫폼 UI
-------------------------------------------------------------------------- */
const JOB_LISTINGS = [
  {
    id: 'j1',
    title: 'Senior Frontend Engineer',
    company: 'Orbit Labs',
    location: '서울, 한국',
    type: 'full-time' as const,
    level: 'Senior',
    salary: '₩80M – ₩120M',
    stack: ['React', 'TypeScript', 'Design System'],
    posted: '2일 전',
    applicants: 42,
    featured: true,
  },
  {
    id: 'j2',
    title: 'UI/UX Designer',
    company: 'DesignCo',
    location: '원격',
    type: 'remote' as const,
    level: 'Mid',
    salary: '₩60M – ₩90M',
    stack: ['Figma', 'Prototyping', 'Design Tokens'],
    posted: '3일 전',
    applicants: 28,
    featured: false,
  },
  {
    id: 'j3',
    title: 'Design System Engineer',
    company: 'TechCorp',
    location: '부산, 한국',
    type: 'hybrid' as const,
    level: 'Mid',
    salary: '₩70M – ₩100M',
    stack: ['vanilla-extract', 'Storybook', 'React'],
    posted: '1주일 전',
    applicants: 15,
    featured: false,
  },
  {
    id: 'j4',
    title: 'Product Manager',
    company: 'StartupXYZ',
    location: '서울, 한국',
    type: 'full-time' as const,
    level: 'Senior',
    salary: '₩90M – ₩130M',
    stack: ['Product Strategy', 'Analytics', 'Agile'],
    posted: '5일 전',
    applicants: 67,
    featured: true,
  },
]

const JOB_TYPE_CONFIG = {
  'full-time': { label: '정규직', color: '#6366f1', bg: '#eef2ff' },
  'remote': { label: '원격', color: '#10b981', bg: '#f0fdf4' },
  'hybrid': { label: '하이브리드', color: '#0ea5e9', bg: '#f0f9ff' },
}

const JobBoardRender = () => {
  const [selectedJob, setSelectedJob] = useState(JOB_LISTINGS[0])
  const [appliedJobs, setAppliedJobs] = useState<Set<string>>(new Set())
  const [savedJobs, setSavedJobs] = useState<Set<string>>(new Set())
  const [searchQuery, setSearchQuery] = useState('')
  const [filterType, setFilterType] = useState<string>('all')
  const [applying, setApplying] = useState(false)

  const filteredJobs = JOB_LISTINGS.filter((j) => {
    const matchSearch = j.title.toLowerCase().includes(searchQuery.toLowerCase()) || j.company.toLowerCase().includes(searchQuery.toLowerCase())
    const matchType = filterType === 'all' || j.type === filterType
    return matchSearch && matchType
  })

  const handleApply = () => {
    setApplying(true)
    setTimeout(() => {
      setAppliedJobs((prev) => new Set([...prev, selectedJob.id]))
      setApplying(false)
    }, 1500)
  }

  const toggleSave = (id: string) => {
    setSavedJobs((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  return (
    <div style={{ maxWidth: 960, fontFamily: 'system-ui, sans-serif' }}>
      {/* 헤더 */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 16, marginBottom: 24, flexWrap: 'wrap' }}>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 24, fontWeight: 900, color: '#0f172a', letterSpacing: '-0.02em', marginBottom: 2 }}>
            채용 공고
          </div>
          <div style={{ fontSize: 13, color: '#64748b' }}>
            {filteredJobs.length}개의 공고 발견
          </div>
        </div>

        <SearchBar
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          placeholder="직무, 회사 검색..."
        />

        <div style={{ display: 'flex', gap: 6 }}>
          {(['all', 'full-time', 'remote', 'hybrid'] as const).map((type) => (
            <button
              key={type}
              onClick={() => setFilterType(type)}
              style={{
                padding: '6px 12px', borderRadius: 8, fontSize: 12, fontWeight: 600, cursor: 'pointer',
                border: `1.5px solid ${filterType === type ? '#6366f1' : '#e2e8f0'}`,
                background: filterType === type ? '#6366f1' : '#fff',
                color: filterType === type ? '#fff' : '#64748b',
                transition: 'all 0.15s',
              }}
            >
              {type === 'all' ? '전체' : JOB_TYPE_CONFIG[type].label}
            </button>
          ))}
        </div>
      </div>

      {/* 메인 레이아웃 */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: 20, alignItems: 'start' }}>
        {/* 공고 목록 */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {filteredJobs.length === 0 ? (
            <div style={{ padding: 48, textAlign: 'center', color: '#94a3b8', background: '#f8fafc', borderRadius: 12, border: '1px dashed #e2e8f0' }}>
              검색 결과가 없습니다.
            </div>
          ) : filteredJobs.map((job) => {
            const typeConfig = JOB_TYPE_CONFIG[job.type]
            const isSelected = selectedJob.id === job.id
            const isApplied = appliedJobs.has(job.id)
            const isSaved = savedJobs.has(job.id)

            return (
              <div
                key={job.id}
                onClick={() => setSelectedJob(job)}
                style={{
                  padding: '18px 20px',
                  borderRadius: 14,
                  border: `2px solid ${isSelected ? '#6366f1' : '#e2e8f0'}`,
                  background: isSelected ? 'rgba(99,102,241,0.03)' : '#fff',
                  cursor: 'pointer',
                  transition: 'all 0.15s',
                  position: 'relative',
                }}
              >
                {job.featured && (
                  <div style={{ position: 'absolute', top: -1, right: 16, background: '#f59e0b', color: '#fff', fontSize: 9, fontWeight: 800, padding: '2px 8px', borderRadius: '0 0 6px 6px' }}>
                    FEATURED
                  </div>
                )}

                <div style={{ display: 'flex', alignItems: 'flex-start', gap: 14 }}>
                  <div style={{
                    width: 44, height: 44, borderRadius: 10, background: `${typeConfig.color}15`,
                    display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, fontSize: 18,
                  }}>
                    {job.type === 'remote' ? '🌐' : job.type === 'hybrid' ? '🏢' : '💼'}
                  </div>

                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4 }}>
                      <div style={{ fontSize: 14, fontWeight: 700, color: '#0f172a' }}>{job.title}</div>
                      {isApplied && (
                        <span style={{ fontSize: 10, fontWeight: 700, color: '#10b981', background: '#dcfce7', padding: '1px 6px', borderRadius: 99 }}>
                          지원완료
                        </span>
                      )}
                    </div>
                    <div style={{ fontSize: 13, color: '#64748b', marginBottom: 8 }}>
                      {job.company} · {job.location}
                    </div>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 10 }}>
                      <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 99, background: typeConfig.bg, color: typeConfig.color, fontWeight: 600 }}>
                        {typeConfig.label}
                      </span>
                      <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 99, background: '#f1f5f9', color: '#64748b', fontWeight: 500 }}>
                        {job.level}
                      </span>
                      {job.stack.slice(0, 2).map((s) => (
                        <Chip key={s}>{s}</Chip>
                      ))}
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                      <span style={{ fontSize: 12, fontWeight: 700, color: '#0f172a' }}>{job.salary}</span>
                      <span style={{ fontSize: 11, color: '#94a3b8' }}>{job.posted}</span>
                      <span style={{ fontSize: 11, color: '#94a3b8', marginLeft: 'auto', fontVariantNumeric: 'tabular-nums' }}>
                        지원자 {job.applicants}명
                      </span>
                    </div>
                  </div>

                  <button
                    onClick={(e) => { e.stopPropagation(); toggleSave(job.id) }}
                    style={{ padding: '6px 8px', borderRadius: 8, border: '1px solid #e2e8f0', background: '#fff', cursor: 'pointer', color: isSaved ? '#f59e0b' : '#94a3b8', fontSize: 14 }}
                  >
                    {isSaved ? '★' : '☆'}
                  </button>
                </div>
              </div>
            )
          })}
        </div>

        {/* 상세 패널 */}
        <div style={{ borderRadius: 16, border: '1px solid #e2e8f0', overflow: 'hidden', position: 'sticky', top: 0 }}>
          <div style={{ padding: '20px', borderBottom: '1px solid #f1f5f9' }}>
            <div style={{ display: 'flex', alignItems: 'flex-start', gap: 12, marginBottom: 14 }}>
              <div style={{
                width: 48, height: 48, borderRadius: 12, background: `${JOB_TYPE_CONFIG[selectedJob.type].color}15`,
                display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, flexShrink: 0,
              }}>
                {selectedJob.type === 'remote' ? '🌐' : selectedJob.type === 'hybrid' ? '🏢' : '💼'}
              </div>
              <div>
                <div style={{ fontSize: 16, fontWeight: 800, color: '#0f172a', marginBottom: 2 }}>{selectedJob.title}</div>
                <div style={{ fontSize: 13, color: '#64748b' }}>{selectedJob.company}</div>
              </div>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginBottom: 16 }}>
              {[
                { label: '위치', value: selectedJob.location },
                { label: '근무형태', value: JOB_TYPE_CONFIG[selectedJob.type].label },
                { label: '레벨', value: selectedJob.level },
                { label: '연봉', value: selectedJob.salary },
              ].map(({ label, value }) => (
                <div key={label} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12 }}>
                  <span style={{ color: '#94a3b8' }}>{label}</span>
                  <span style={{ color: '#374151', fontWeight: 600 }}>{value}</span>
                </div>
              ))}
            </div>

            <div style={{ marginBottom: 16 }}>
              <div style={{ fontSize: 11, fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 8 }}>
                기술 스택
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                {selectedJob.stack.map((s) => (
                  <Chip key={s}>{s}</Chip>
                ))}
              </div>
            </div>

            <Progress value={Math.min(selectedJob.applicants * 1.5, 100)} />
            <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 4, textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
              지원자 {selectedJob.applicants}명 / 정원 {Math.round(selectedJob.applicants * 1.5)}명
            </div>
          </div>

          <div style={{ padding: '16px 20px', borderBottom: '1px solid #f1f5f9' }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: '#1e293b', marginBottom: 8 }}>직무 소개</div>
            <div style={{ fontSize: 12, color: '#64748b', lineHeight: 1.7 }}>
              {selectedJob.company}에서 {selectedJob.level} {selectedJob.title}를 채용합니다.
              3-tier 아키텍처 기반 디자인 시스템 개발 경험이 있는 분을 우대합니다.
              팀 문화를 중시하며 성장 지향적인 환경에서 일하고 싶은 분을 모십니다.
            </div>
          </div>

          <div style={{ padding: '16px 20px' }}>
            <SolidButton
              color="primary"
              size="medium"
              style={{ width: '100%', marginBottom: 10 }}
              disabled={appliedJobs.has(selectedJob.id) || applying}
              onClick={handleApply}
            >
              <SolidButton.Center>
                {applying ? '제출 중...' : appliedJobs.has(selectedJob.id) ? '지원 완료' : '지금 지원하기'}
              </SolidButton.Center>
            </SolidButton>
            <OutlineButton
              color="black"
              size="medium"
              style={{ width: '100%' }}
              onClick={() => toggleSave(selectedJob.id)}
            >
              {savedJobs.has(selectedJob.id) ? '저장 취소' : '공고 저장'}
            </OutlineButton>
          </div>
        </div>
      </div>
    </div>
  )
}

export const JobBoard: Story = {
  name: 'Job Board (MUI + Raycast 벤치마크)',
  render: () => <JobBoardRender />,
}

/* ═══════════════════════════════════════════
   35. Inbox View (Linear + Notion 벤치마크)
   ═══════════════════════════════════════════ */
type InboxItem = {
  id: number
  from: string
  subject: string
  preview: string
  time: string
  unread: boolean
  tag: 'mention' | 'assigned' | 'comment' | 'update'
}

const TAG_CONFIG = {
  mention: { label: '멘션', bg: '#ede9fe', color: '#7c3aed' },
  assigned: { label: '배정됨', bg: '#dbeafe', color: '#1d4ed8' },
  comment: { label: '댓글', bg: '#dcfce7', color: '#16a34a' },
  update: { label: '업데이트', bg: '#fef9c3', color: '#b45309' },
}

const INBOX_ITEMS: InboxItem[] = [
  { id: 1, from: '김민준', subject: 'SolidIconButton 코드 리뷰 요청', preview: '새 스토리 3개 추가했습니다. 검토 부탁드립니다.', time: '5분 전', unread: true, tag: 'mention' },
  { id: 2, from: '이서연', subject: 'PRJ-247 이슈 배정', preview: 'API 레이트리밋 구현 이슈가 배정되었습니다.', time: '23분 전', unread: true, tag: 'assigned' },
  { id: 3, from: '박도현', subject: 'TypeScript 타입 오류 댓글', preview: 'CounterBadge children 타입 문제 확인해 주세요.', time: '1시간 전', unread: false, tag: 'comment' },
  { id: 4, from: '최지아', subject: 'Storybook 빌드 완료', preview: '스테이징 환경 배포가 완료되었습니다.', time: '2시간 전', unread: false, tag: 'update' },
  { id: 5, from: '정우성', subject: '디자인 토큰 업데이트', preview: '컬러 시스템 3.0 리뷰를 요청합니다.', time: '3시간 전', unread: false, tag: 'mention' },
]

const InboxViewRender = () => {
  const [items, setItems] = useState<InboxItem[]>(INBOX_ITEMS)
  const [selectedId, setSelectedId] = useState<number | null>(1)
  const [filter, setFilter] = useState<InboxItem['tag'] | 'all'>('all')

  const filtered = filter === 'all' ? items : items.filter((i) => i.tag === filter)
  const selected = items.find((i) => i.id === selectedId) ?? null
  const unreadCount = items.filter((i) => i.unread).length

  const markRead = (id: number) => {
    setItems((prev) => prev.map((i) => (i.id === id ? { ...i, unread: false } : i)))
    setSelectedId(id)
  }

  const markAllRead = () => setItems((prev) => prev.map((i) => ({ ...i, unread: false })))

  const filterTags: Array<{ key: InboxItem['tag'] | 'all'; label: string }> = [
    { key: 'all', label: '전체' },
    { key: 'mention', label: '멘션' },
    { key: 'assigned', label: '배정됨' },
    { key: 'comment', label: '댓글' },
    { key: 'update', label: '업데이트' },
  ]

  return (
    <div
      style={{
        display: 'flex',
        height: 560,
        background: tc.bg,
        borderRadius: 12,
        border: `1px solid ${tc.border}`,
        overflow: 'hidden',
        fontFamily: 'system-ui, sans-serif',
      }}
    >
      {/* Left Panel */}
      <div style={{ width: 320, borderRight: `1px solid ${tc.border}`, display: 'flex', flexDirection: 'column' }}>
        {/* Header */}
        <div
          style={{
            padding: '14px 16px',
            borderBottom: `1px solid ${tc.border}`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
          }}
        >
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ fontWeight: 700, fontSize: 15, color: tc.fg }}>받은 알림</span>
            {unreadCount > 0 && (
              <CounterBadge color="red">
                {unreadCount}
              </CounterBadge>
            )}
          </div>
          <SolidIconButton color="white" size="small" onClick={markAllRead} aria-label="모두 읽음">
            <CheckIcon />
          </SolidIconButton>
        </div>
        {/* Filter Tabs */}
        <div
          style={{
            display: 'flex',
            gap: 4,
            padding: '8px 12px',
            borderBottom: `1px solid ${tc.border}`,
            flexWrap: 'wrap',
          }}
        >
          {filterTags.map((f) => (
            <button
              key={f.key}
              onClick={() => setFilter(f.key)}
              style={{
                padding: '3px 10px',
                borderRadius: 20,
                border: 'none',
                cursor: 'pointer',
                fontSize: 11,
                fontWeight: 600,
                background: filter === f.key ? '#1e293b' : tc.surface,
                color: filter === f.key ? '#fff' : tc.fgSub,
                transition: 'all 0.15s',
              }}
            >
              {f.label}
            </button>
          ))}
        </div>
        {/* List */}
        <div style={{ flex: 1, overflowY: 'auto' }}>
          {filtered.map((item) => {
            const tag = TAG_CONFIG[item.tag]
            return (
              <div
                key={item.id}
                onClick={() => markRead(item.id)}
                style={{
                  padding: '12px 16px',
                  borderBottom: `1px solid ${tc.borderSub}`,
                  cursor: 'pointer',
                  background: selectedId === item.id ? tc.surface : 'transparent',
                  borderLeft: item.unread ? '3px solid #6366f1' : '3px solid transparent',
                  transition: 'background 0.1s',
                }}
              >
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 4 }}>
                  <span style={{ fontWeight: item.unread ? 700 : 500, fontSize: 13, color: tc.fg }}>{item.from}</span>
                  <span style={{ fontSize: 10, color: tc.fgMuted }}>{item.time}</span>
                </div>
                <div style={{ fontSize: 12, fontWeight: item.unread ? 600 : 400, color: tc.fg, marginBottom: 4 }}>{item.subject}</div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <span
                    style={{
                      fontSize: 10,
                      fontWeight: 600,
                      padding: '1px 6px',
                      borderRadius: 4,
                      background: tag.bg,
                      color: tag.color,
                    }}
                  >
                    {tag.label}
                  </span>
                  <span style={{ fontSize: 11, color: tc.fgMuted, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1 }}>
                    {item.preview}
                  </span>
                </div>
              </div>
            )
          })}
          {filtered.length === 0 && (
            <div style={{ padding: 32, textAlign: 'center', color: tc.fgMuted, fontSize: 13 }}>알림 없음</div>
          )}
        </div>
      </div>

      {/* Right Panel */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
        {selected ? (
          <>
            <div
              style={{
                padding: '14px 20px',
                borderBottom: `1px solid ${tc.border}`,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
              }}
            >
              <div>
                <div style={{ fontWeight: 700, fontSize: 15, color: tc.fg, marginBottom: 2 }}>{selected.subject}</div>
                <div style={{ fontSize: 12, color: tc.fgSub }}>
                  {selected.from} · {selected.time}
                </div>
              </div>
              <div style={{ display: 'flex', gap: 4 }}>
                <SolidIconButton color="white" size="small" aria-label="공유">
                  <ShareIcon />
                </SolidIconButton>
                <SolidIconButton color="white" size="small" aria-label="더보기">
                  <MoreHorizontalIcon />
                </SolidIconButton>
              </div>
            </div>
            <div style={{ flex: 1, padding: '24px 28px', overflowY: 'auto' }}>
              <div
                style={{
                  background: tc.surface,
                  borderRadius: 10,
                  padding: '16px 20px',
                  fontSize: 14,
                  color: tc.fg,
                  lineHeight: 1.7,
                  border: `1px solid ${tc.border}`,
                }}
              >
                {selected.preview}
              </div>
              <div
                style={{
                  marginTop: 20,
                  padding: '14px 18px',
                  background: tc.bg,
                  borderRadius: 8,
                  border: `1px solid ${tc.border}`,
                }}
              >
                <div style={{ fontSize: 12, color: tc.fgSub, marginBottom: 10 }}>빠른 회신</div>
                <div style={{ width: '100%', marginBottom: 10 }}>
                  <TextArea
                    rows={3}
                    placeholder="회신 내용을 입력하세요..."
                  />
                </div>
                <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8 }}>
                  <SolidButton color="primary" size="small">
                    <SolidButton.Center>회신 보내기</SolidButton.Center>
                  </SolidButton>
                </div>
              </div>
            </div>
          </>
        ) : (
          <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', color: tc.fgMuted, fontSize: 14 }}>
            알림을 선택하세요
          </div>
        )}
      </div>
    </div>
  )
}

export const InboxView: Story = {
  name: 'Inbox View (Linear + Notion 벤치마크)',
  render: () => <InboxViewRender />,
}

/* ═══════════════════════════════════════════
   36. Sprint Board (Vercel + Ant Design 벤치마크)
   ═══════════════════════════════════════════ */
type SprintColStatus = 'backlog' | 'inprogress' | 'review' | 'done'

type SprintCard = {
  id: number
  title: string
  tag: string
  tagColor: string
  priority: 'high' | 'medium' | 'low'
  assignee: string
}

const SPRINT_PRIORITY_CONFIG = {
  high: { label: '높음', bg: '#fef2f2', color: '#dc2626' },
  medium: { label: '보통', bg: '#fffbeb', color: '#d97706' },
  low: { label: '낮음', bg: '#f0fdf4', color: '#16a34a' },
}

const INITIAL_SPRINT: Record<SprintColStatus, SprintCard[]> = {
  backlog: [
    { id: 1, title: 'Space 컴포넌트 스토리 추가', tag: '문서', tagColor: '#6366f1', priority: 'medium', assignee: '김' },
    { id: 2, title: 'AlertDialog 다단계 확인 구현', tag: '기능', tagColor: '#06b6d4', priority: 'high', assignee: '이' },
  ],
  inprogress: [
    { id: 3, title: 'Vercel 배포 파이프라인 설정', tag: '인프라', tagColor: '#f59e0b', priority: 'high', assignee: '박' },
    { id: 4, title: '디자인 토큰 MDX 보강', tag: '문서', tagColor: '#6366f1', priority: 'low', assignee: '최' },
  ],
  review: [
    { id: 5, title: 'TypeScript 타입 정리', tag: '리팩터', tagColor: '#8b5cf6', priority: 'medium', assignee: '정' },
  ],
  done: [
    { id: 6, title: 'Cycle 45 배포 완료', tag: '배포', tagColor: '#10b981', priority: 'low', assignee: '김' },
    { id: 7, title: 'SolidIconButton 스토리 고도화', tag: '기능', tagColor: '#06b6d4', priority: 'medium', assignee: '이' },
  ],
}

const SPRINT_COL_CONFIG: Record<SprintColStatus, { label: string; dotColor: string }> = {
  backlog: { label: 'Backlog', dotColor: '#94a3b8' },
  inprogress: { label: 'In Progress', dotColor: '#f59e0b' },
  review: { label: 'Review', dotColor: '#6366f1' },
  done: { label: 'Done', dotColor: '#10b981' },
}

const SPRINT_COLUMNS: SprintColStatus[] = ['backlog', 'inprogress', 'review', 'done']

const SprintBoardRender = () => {
  const [board, setBoard] = useState<Record<SprintColStatus, SprintCard[]>>(INITIAL_SPRINT)
  const [dragging, setDragging] = useState<{ card: SprintCard; from: SprintColStatus } | null>(null)
  const [dragOver, setDragOver] = useState<SprintColStatus | null>(null)
  const [filter, setFilter] = useState<'all' | 'high' | 'medium' | 'low'>('all')

  const totalCards = SPRINT_COLUMNS.reduce((sum, col) => sum + board[col].length, 0)
  const doneCards = board.done.length

  const filteredBoard = (col: SprintColStatus) =>
    filter === 'all' ? board[col] : board[col].filter((c) => c.priority === filter)

  const handleDragStart = (card: SprintCard, from: SprintColStatus) => setDragging({ card, from })

  const handleDrop = (to: SprintColStatus) => {
    if (!dragging || dragging.from === to) { setDragging(null); return }
    setBoard((prev) => {
      const fromCards = prev[dragging.from].filter((c) => c.id !== dragging.card.id)
      const toCards = [...prev[to], dragging.card]
      return { ...prev, [dragging.from]: fromCards, [to]: toCards }
    })
    setDragging(null)
    setDragOver(null)
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', background: tc.surface, minHeight: 520, borderRadius: 12, overflow: 'hidden', border: `1px solid ${tc.border}` }}>
      {/* Header */}
      <div style={{ padding: '14px 20px', borderBottom: `1px solid ${tc.border}`, background: tc.bg, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontWeight: 700, fontSize: 15, color: tc.fg }}>Sprint Board</span>
          <Progress value={Math.round((doneCards / totalCards) * 100)} color="primary" size="small" style={{ width: 80 }} />
          <span style={{ fontSize: 12, color: tc.fgSub }}>{doneCards}/{totalCards} 완료</span>
        </div>
        <div style={{ display: 'flex', gap: 4 }}>
          {(['all', 'high', 'medium', 'low'] as const).map((f) => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              style={{
                padding: '3px 10px', borderRadius: 20, border: 'none', cursor: 'pointer',
                fontSize: 11, fontWeight: 600,
                background: filter === f ? '#1e293b' : tc.surface,
                color: filter === f ? '#fff' : tc.fgSub,
                transition: 'all 0.15s',
              }}
            >
              {f === 'all' ? '전체' : SPRINT_PRIORITY_CONFIG[f].label}
            </button>
          ))}
        </div>
      </div>

      {/* Columns */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12, padding: 16, overflowX: 'auto' }}>
        {SPRINT_COLUMNS.map((col) => {
          const config = SPRINT_COL_CONFIG[col]
          const cards = filteredBoard(col)
          const isOver = dragOver === col

          return (
            <div
              key={col}
              onDragOver={(e) => { e.preventDefault(); setDragOver(col) }}
              onDragLeave={() => setDragOver(null)}
              onDrop={() => handleDrop(col)}
              style={{
                background: isOver ? '#f0f9ff' : tc.bg,
                borderRadius: 10,
                border: `1px solid ${isOver ? '#6366f1' : tc.border}`,
                transition: 'all 0.15s',
                minHeight: 200,
              }}
            >
              {/* Column header */}
              <div style={{ padding: '10px 12px', borderBottom: `1px solid ${tc.borderSub}`, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <div style={{ width: 8, height: 8, borderRadius: '50%', background: config.dotColor }} />
                  <span style={{ fontSize: 12, fontWeight: 700, color: tc.fg }}>{config.label}</span>
                </div>
                <CounterBadge color="gray">{board[col].length}</CounterBadge>
              </div>

              {/* Cards */}
              <div style={{ padding: 8, display: 'flex', flexDirection: 'column', gap: 8 }}>
                {cards.map((card) => {
                  const pri = SPRINT_PRIORITY_CONFIG[card.priority]
                  return (
                    <div
                      key={card.id}
                      draggable
                      onDragStart={() => handleDragStart(card, col)}
                      style={{
                        background: tc.bg,
                        borderRadius: 8,
                        border: `1px solid ${tc.border}`,
                        padding: '10px 12px',
                        cursor: 'grab',
                        boxShadow: '0 1px 3px rgba(0,0,0,0.06)',
                        opacity: dragging?.card.id === card.id ? 0.5 : 1,
                        transition: 'opacity 0.15s',
                      }}
                    >
                      <div style={{ fontSize: 12, fontWeight: 600, color: tc.fg, marginBottom: 8, lineHeight: 1.4 }}>{card.title}</div>
                      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                          <span style={{
                            fontSize: 10, fontWeight: 600, padding: '1px 6px', borderRadius: 4,
                            background: `${card.tagColor}18`, color: card.tagColor,
                          }}>
                            {card.tag}
                          </span>
                          <span style={{
                            fontSize: 10, fontWeight: 600, padding: '1px 6px', borderRadius: 4,
                            background: pri.bg, color: pri.color,
                          }}>
                            {pri.label}
                          </span>
                        </div>
                        <div style={{
                          width: 20, height: 20, borderRadius: '50%',
                          background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
                          color: '#fff', fontSize: 10, fontWeight: 700,
                          display: 'flex', alignItems: 'center', justifyContent: 'center',
                        }}>
                          {card.assignee}
                        </div>
                      </div>
                    </div>
                  )
                })}
                {cards.length === 0 && (
                  <div style={{ padding: '20px 0', textAlign: 'center', color: tc.fgMuted, fontSize: 12 }}>
                    {filter !== 'all' ? '필터된 항목 없음' : '카드 없음'}
                  </div>
                )}
              </div>
            </div>
          )
        })}
      </div>
    </div>
  )
}

