/* ==========================================================================
   Template #59: HabitTracker — 습관 추적 & 목표 관리 대시보드
   Linear Design + Google Material 3 벤치마크 기반
   ========================================================================== */
type HabitFreq = 'daily' | 'weekly'
type HabitStatus = 'active' | 'paused'

type Habit = {
  id: number
  name: string
  freq: HabitFreq
  streak: number
  target: number
  completedToday: boolean
  status: HabitStatus
  color: string
  weekHistory: boolean[]
}

const INITIAL_HABITS: Habit[] = [
  { id: 1, name: '물 2L 마시기', freq: 'daily', streak: 12, target: 30, completedToday: true, status: 'active', color: '#0ea5e9', weekHistory: [true, true, false, true, true, true, true] },
  { id: 2, name: '30분 운동', freq: 'daily', streak: 5, target: 21, completedToday: false, status: 'active', color: '#22c55e', weekHistory: [true, false, true, true, false, true, false] },
  { id: 3, name: '독서 20페이지', freq: 'daily', streak: 3, target: 14, completedToday: true, status: 'active', color: '#6366f1', weekHistory: [false, true, true, false, true, false, true] },
  { id: 4, name: '주간 프로젝트 리뷰', freq: 'weekly', streak: 8, target: 12, completedToday: false, status: 'active', color: '#f59e0b', weekHistory: [false, false, false, false, false, false, true] },
  { id: 5, name: '명상 10분', freq: 'daily', streak: 0, target: 7, completedToday: false, status: 'paused', color: '#94a3b8', weekHistory: [false, false, false, false, false, false, false] },
]

const WEEK_LABELS = ['월', '화', '수', '목', '금', '토', '일']

const HabitTrackerRender = () => {
  const [habits, setHabits] = useState<Habit[]>(INITIAL_HABITS)
  const [filter, setFilter] = useState<'all' | 'daily' | 'weekly'>('all')
  const [showNewForm, setShowNewForm] = useState(false)
  const [newHabitName, setNewHabitName] = useState('')

  const toggleComplete = (id: number) => {
    setHabits((prev) =>
      prev.map((h) =>
        h.id === id
          ? {
              ...h,
              completedToday: !h.completedToday,
              streak: !h.completedToday ? h.streak + 1 : Math.max(0, h.streak - 1),
            }
          : h,
      ),
    )
  }

  const addHabit = () => {
    if (!newHabitName.trim()) return
    const colors = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#0ea5e9']
    const newHabit: Habit = {
      id: Date.now(),
      name: newHabitName.trim(),
      freq: 'daily',
      streak: 0,
      target: 21,
      completedToday: false,
      status: 'active',
      color: colors[habits.length % colors.length],
      weekHistory: [false, false, false, false, false, false, false],
    }
    setHabits((prev) => [...prev, newHabit])
    setNewHabitName('')
    setShowNewForm(false)
  }

  const filtered = habits.filter((h) => filter === 'all' || h.freq === filter)
  const completedCount = filtered.filter((h) => h.completedToday && h.status === 'active').length
  const activeCount = filtered.filter((h) => h.status === 'active').length
  const todayPct = activeCount > 0 ? Math.round((completedCount / activeCount) * 100) : 0

  return (
    <div style={{ minHeight: '100vh', background: '#f8fafc', fontFamily: 'system-ui, sans-serif' }}>
      {/* 헤더 */}
      <div style={{ background: '#fff', borderBottom: '1px solid #e2e8f0', padding: '16px 28px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 800, color: '#0f172a' }}>습관 트래커</div>
          <div style={{ fontSize: 12, color: '#94a3b8', marginTop: 2 }}>2026년 4월 10일 · 목요일</div>
        </div>
        <SolidButton color="primary" size="small" onClick={() => setShowNewForm(true)}>
          <SolidButton.Center>새 습관 추가</SolidButton.Center>
        </SolidButton>
      </div>

      <div style={{ padding: '24px 28px', maxWidth: 900, margin: '0 auto' }}>
        {/* 오늘의 요약 */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 14, marginBottom: 28 }}>
          <div style={{ background: '#fff', borderRadius: 14, border: '1px solid #e2e8f0', padding: '20px 20px', gridColumn: 'span 2' }}>
            <div style={{ fontSize: 12, fontWeight: 600, color: '#94a3b8', marginBottom: 12 }}>오늘의 진행률</div>
            <div style={{ fontSize: 32, fontWeight: 900, color: todayPct === 100 ? '#22c55e' : '#0f172a', marginBottom: 10 }}>
              {todayPct}%
            </div>
            <Progress value={todayPct} max={100} />
            <div style={{ fontSize: 12, color: '#64748b', marginTop: 8 }}>
              {completedCount}/{activeCount} 완료
            </div>
          </div>
          {[
            { label: '최장 연속 달성', value: `${Math.max(...habits.map((h) => h.streak))}일`, color: '#6366f1' },
            { label: '활성 습관', value: `${habits.filter((h) => h.status === 'active').length}개`, color: '#0ea5e9' },
          ].map((stat) => (
            <div key={stat.label} style={{ background: '#fff', borderRadius: 14, border: '1px solid #e2e8f0', padding: '20px 20px' }}>
              <div style={{ fontSize: 12, fontWeight: 600, color: '#94a3b8', marginBottom: 12 }}>{stat.label}</div>
              <div style={{ fontSize: 28, fontWeight: 800, color: stat.color }}>{stat.value}</div>
            </div>
          ))}
        </div>

        {/* 필터 탭 */}
        <div style={{ display: 'flex', gap: 4, marginBottom: 20 }}>
          {(['all', 'daily', 'weekly'] as const).map((f) => (
            <button
              key={f}
              onClick={() => setFilter(f)}
              style={{
                padding: '7px 16px', borderRadius: 8, fontSize: 13, fontWeight: 600, border: 'none',
                background: filter === f ? '#0f172a' : '#f1f5f9',
                color: filter === f ? '#fff' : '#64748b',
                cursor: 'pointer', transition: 'all 0.15s',
              }}
            >
              {f === 'all' ? '전체' : f === 'daily' ? '매일' : '매주'}
            </button>
          ))}
        </div>

        {/* 새 습관 폼 */}
        {showNewForm && (
          <div style={{ background: '#fff', borderRadius: 14, border: '2px solid #6366f1', padding: '16px 20px', marginBottom: 16, display: 'flex', gap: 10 }}>
            <input
              value={newHabitName}
              onChange={(e) => setNewHabitName(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter') addHabit() }}
              placeholder="새 습관 이름 입력..."
              autoFocus
              style={{ flex: 1, padding: '8px 12px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 13, outline: 'none' }}
            />
            <SolidButton color="primary" size="small" onClick={addHabit}>
              <SolidButton.Center>추가</SolidButton.Center>
            </SolidButton>
            <OutlineButton color="gray" size="small" onClick={() => setShowNewForm(false)}>
              <OutlineButton.Center>취소</OutlineButton.Center>
            </OutlineButton>
          </div>
        )}

        {/* 습관 목록 */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          {filtered.map((habit, idx) => {
            const pct = Math.round((habit.streak / habit.target) * 100)
            return (
              <div key={habit.id}>
                <div style={{
                  background: habit.status === 'paused' ? '#f8fafc' : '#fff',
                  borderRadius: 14, border: '1px solid #e2e8f0', padding: '16px 20px',
                  display: 'flex', alignItems: 'center', gap: 16,
                  opacity: habit.status === 'paused' ? 0.6 : 1,
                }}>
                  {/* 완료 토글 */}
                  <button
                    onClick={() => habit.status === 'active' && toggleComplete(habit.id)}
                    disabled={habit.status === 'paused'}
                    style={{
                      width: 28, height: 28, borderRadius: '50%', flexShrink: 0,
                      border: `2px solid ${habit.completedToday ? habit.color : '#e2e8f0'}`,
                      background: habit.completedToday ? habit.color : '#fff',
                      cursor: habit.status === 'active' ? 'pointer' : 'not-allowed',
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      transition: 'all 0.2s', color: '#fff', fontSize: 12,
                    }}
                  >
                    {habit.completedToday && '✓'}
                  </button>

                  {/* 정보 */}
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
                      <span style={{ fontSize: 14, fontWeight: 600, color: '#0f172a', textDecoration: habit.completedToday ? 'line-through' : 'none' }}>
                        {habit.name}
                      </span>
                      <span style={{ fontSize: 10, padding: '1px 6px', borderRadius: 99, background: habit.freq === 'daily' ? '#eff6ff' : '#fef3c7', color: habit.freq === 'daily' ? '#3730a3' : '#92400e', fontWeight: 600 }}>
                        {habit.freq === 'daily' ? '매일' : '매주'}
                      </span>
                      {habit.status === 'paused' && (
                        <span style={{ fontSize: 10, padding: '1px 6px', borderRadius: 99, background: '#f1f5f9', color: '#94a3b8', fontWeight: 600 }}>일시정지</span>
                      )}
                    </div>

                    {/* 주간 히스토리 */}
                    <div style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
                      {WEEK_LABELS.map((day, i) => (
                        <div key={day} style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2 }}>
                          <div style={{
                            width: 20, height: 20, borderRadius: 4,
                            background: habit.weekHistory[i] ? habit.color : '#f1f5f9',
                            transition: 'background 0.2s',
                          }} />
                          <span style={{ fontSize: 9, color: '#94a3b8' }}>{day}</span>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* 스트릭 + 진행률 */}
                  <div style={{ textAlign: 'right', flexShrink: 0, minWidth: 80 }}>
                    <div style={{ fontSize: 20, fontWeight: 800, color: habit.color }}>{habit.streak}일</div>
                    <div style={{ fontSize: 10, color: '#94a3b8', marginBottom: 6 }}>목표 {habit.target}일 중</div>
                    <div style={{ height: 4, background: '#f1f5f9', borderRadius: 2, width: 80 }}>
                      <div style={{ height: '100%', width: `${Math.min(100, pct)}%`, background: habit.color, borderRadius: 2, transition: 'width 0.3s' }} />
                    </div>
                  </div>
                </div>
                {/* Linear 스타일 구분선 (마지막 제외) */}
                {idx < filtered.length - 1 && (
                  <div style={{ height: 1, background: 'transparent', margin: '0 20px' }} />
                )}
              </div>
            )
          })}
        </div>

        {/* PageDots 페이지 인디케이터 */}
        <div style={{ display: 'flex', justifyContent: 'center', gap: 8, marginTop: 28 }}>
          {[0, 1, 2].map((i) => (
            <PageDots key={i} selected={i === 0} onClick={() => {}} />
          ))}
        </div>
      </div>
    </div>
  )
}

export const HabitTracker: Story = {
  name: '습관 트래커 & 목표 관리 (Linear + M3 패턴)',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        story: 'Linear 상태 관리 패턴 + Material 3 진행률 시각화 기반 습관 추적 대시보드. 완료 토글, 주간 히트맵, 연속 달성일, Progress 바, PageDots 인디케이터 포함.',
      },
    },
  },
  render: () => <HabitTrackerRender />,
}

/* ==========================================================================
   Template #60 — NotificationCenter (알림 센터)
   Tailwind UI + Ant Design 패턴: 읽음/안읽음 관리, 카테고리 필터, 일괄 액션
   ========================================================================== */
type NotiType = 'info' | 'success' | 'warning' | 'mention'
type NotiCategory = 'all' | 'system' | 'team' | 'updates'

type Notification = {
  id: string
  type: NotiType
  category: Exclude<NotiCategory, 'all'>
  title: string
  body: string
  time: string
  read: boolean
  avatar: string
  avatarBg: string
}

const NOTI_TYPE_CFG: Record<NotiType, { label: string; color: string; dot: string }> = {
  info:    { label: '정보',   color: '#3b82f6', dot: '#bfdbfe' },
  success: { label: '완료',   color: '#10b981', dot: '#a7f3d0' },
  warning: { label: '경고',   color: '#f59e0b', dot: '#fde68a' },
  mention: { label: '멘션',   color: '#8b5cf6', dot: '#ddd6fe' },
}

const NOTI_CAT_LABELS: Record<NotiCategory, string> = {
  all: '전체', system: '시스템', team: '팀', updates: '업데이트',
}

const INITIAL_NOTIS: Notification[] = [
  { id: 'n1', type: 'mention', category: 'team', title: '김지훈님이 회원님을 멘션했습니다', body: '"@you 이 컴포넌트 API 리뷰해줄 수 있나요?"', time: '방금', read: false, avatar: 'KJ', avatarBg: '#6366f1' },
  { id: 'n2', type: 'success', category: 'system', title: '배포 성공', body: 'production 브랜치가 성공적으로 배포되었습니다. v3.2.1', time: '5분 전', read: false, avatar: 'CD', avatarBg: '#10b981' },
  { id: 'n3', type: 'warning', category: 'system', title: 'API 한도 90% 도달', body: '이번 달 API 요청이 90%에 도달했습니다. 플랜 업그레이드를 고려하세요.', time: '1시간 전', read: false, avatar: '!', avatarBg: '#f59e0b' },
  { id: 'n4', type: 'info', category: 'updates', title: '새 기능 출시: 다크 모드', body: 'Eclipse 테마에 다크 모드 지원이 추가되었습니다. 설정에서 전환하세요.', time: '3시간 전', read: true, avatar: 'OR', avatarBg: '#0ea5e9' },
  { id: 'n5', type: 'mention', category: 'team', title: '이수연님이 PR을 할당했습니다', body: 'PR #142: DataTable 성능 최적화를 검토해 주세요.', time: '어제', read: true, avatar: 'LS', avatarBg: '#ec4899' },
  { id: 'n6', type: 'success', category: 'team', title: '코드 리뷰 승인', body: '박민준님이 PR #138 컴포넌트 접근성 개선을 승인했습니다.', time: '어제', read: true, avatar: 'PM', avatarBg: '#8b5cf6' },
  { id: 'n7', type: 'info', category: 'updates', title: '주간 리포트 준비 완료', body: '지난 주 팀 활동 요약 리포트를 확인하세요. 47개 태스크 완료.', time: '2일 전', read: true, avatar: 'RP', avatarBg: '#64748b' },
]

const NotiCenterRender = () => {
  const [notis, setNotis] = React.useState<Notification[]>(INITIAL_NOTIS)
  const [cat, setCat] = React.useState<NotiCategory>('all')
  const [showUnreadOnly, setShowUnreadOnly] = React.useState(false)

  const filtered = notis.filter((n) => {
    if (cat !== 'all' && n.category !== cat) return false
    if (showUnreadOnly && n.read) return false
    return true
  })

  const unreadCount = notis.filter((n) => !n.read).length

  const markAllRead = () => setNotis((prev) => prev.map((n) => ({ ...n, read: true })))
  const markRead = (id: string) => setNotis((prev) => prev.map((n) => n.id === id ? { ...n, read: true } : n))
  const deleteNoti = (id: string) => setNotis((prev) => prev.filter((n) => n.id !== id))

  return (
    <div style={{ minHeight: '100vh', background: '#f8fafc', display: 'flex', justifyContent: 'center', padding: '24px 16px' }}>
      <div style={{ width: '100%', maxWidth: 640 }}>
        {/* 헤더 */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={{ fontSize: 20, fontWeight: 800, color: '#0f172a' }}>알림</span>
            {unreadCount > 0 && (
              <span style={{ fontSize: 11, fontWeight: 700, padding: '2px 8px', borderRadius: 99, background: '#6366f1', color: '#fff' }}>{unreadCount}</span>
            )}
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <GhostButton color="black" size="small" onClick={() => setShowUnreadOnly((v) => !v)}>
              <GhostButton.Center>{showUnreadOnly ? '전체 보기' : '안읽음만'}</GhostButton.Center>
            </GhostButton>
            {unreadCount > 0 && (
              <OutlineButton size="small" color="black" onClick={markAllRead}>
                <OutlineButton.Center>모두 읽음</OutlineButton.Center>
              </OutlineButton>
            )}
          </div>
        </div>

        {/* 카테고리 탭 */}
        <div style={{ display: 'flex', gap: 4, marginBottom: 16, background: '#fff', borderRadius: 10, padding: 4, border: '1px solid #e2e8f0' }}>
          {(Object.keys(NOTI_CAT_LABELS) as NotiCategory[]).map((c) => {
            const cnt = c === 'all' ? notis.filter((n) => !n.read).length : notis.filter((n) => n.category === c && !n.read).length
            return (
              <button key={c} onClick={() => setCat(c)} style={{ flex: 1, padding: '7px 4px', borderRadius: 7, border: 'none', cursor: 'pointer', fontSize: 13, fontWeight: cat === c ? 700 : 400, background: cat === c ? '#0f172a' : 'transparent', color: cat === c ? '#fff' : '#64748b', transition: 'all 0.2s', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 4 }}>
                {NOTI_CAT_LABELS[c]}
                {cnt > 0 && <span style={{ fontSize: 10, fontWeight: 700, minWidth: 16, height: 16, borderRadius: 99, background: cat === c ? 'rgba(255,255,255,0.25)' : '#e0e7ff', color: cat === c ? '#fff' : '#6366f1', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', padding: '0 4px' }}>{cnt}</span>}
              </button>
            )
          })}
        </div>

        {/* 알림 목록 */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {filtered.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '60px 0', color: '#94a3b8', fontSize: 14 }}>
              알림이 없습니다
            </div>
          ) : (
            filtered.map((n) => {
              const cfg = NOTI_TYPE_CFG[n.type]
              return (
                <div key={n.id} onClick={() => markRead(n.id)} style={{ background: '#fff', borderRadius: 12, border: `1px solid ${n.read ? '#e2e8f0' : '#c7d2fe'}`, padding: '16px', display: 'flex', gap: 12, cursor: 'pointer', transition: 'all 0.2s', position: 'relative', opacity: n.read ? 0.75 : 1 }}>
                  {/* 읽음 상태 도트 */}
                  {!n.read && (
                    <span style={{ position: 'absolute', top: 16, right: 16, width: 8, height: 8, borderRadius: '50%', background: cfg.color }} />
                  )}
                  {/* 아바타 */}
                  <div style={{ width: 40, height: 40, borderRadius: '50%', background: n.avatarBg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 13, fontWeight: 800, color: '#fff', flexShrink: 0 }}>
                    {n.avatar}
                  </div>
                  {/* 콘텐츠 */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 4 }}>
                      <span style={{ fontSize: 9, fontWeight: 700, padding: '2px 6px', borderRadius: 4, background: cfg.dot, color: cfg.color }}>{cfg.label}</span>
                      <span style={{ fontSize: 12, color: '#94a3b8' }}>{n.time}</span>
                    </div>
                    <div style={{ fontSize: 14, fontWeight: n.read ? 400 : 700, color: '#0f172a', marginBottom: 4 }}>{n.title}</div>
                    <div style={{ fontSize: 13, color: '#64748b', lineHeight: 1.5 }}>{n.body}</div>
                  </div>
                  {/* 삭제 버튼 */}
                  <button onClick={(e) => { e.stopPropagation(); deleteNoti(n.id) }} style={{ position: 'absolute', top: 12, right: n.read ? 12 : 26, background: 'none', border: 'none', cursor: 'pointer', fontSize: 16, color: '#cbd5e1', lineHeight: 1, padding: '2px 4px', borderRadius: 4 }} title="삭제">x</button>
                </div>
              )
            })
          )}
        </div>

        {/* 하단 Progress */}
        {unreadCount > 0 && (
          <div style={{ marginTop: 24, padding: '16px', background: '#fff', borderRadius: 12, border: '1px solid #e2e8f0' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8, fontSize: 13 }}>
              <span style={{ color: '#64748b' }}>읽음 완료</span>
              <span style={{ fontWeight: 700, color: '#0f172a' }}>{notis.length - unreadCount} / {notis.length}</span>
            </div>
            <Progress value={Math.round((notis.length - unreadCount) / notis.length * 100)} />
          </div>
        )}
      </div>
    </div>
  )
}

export const TailwindNotificationCenter: Story = {
  name: '알림 센터 (Tailwind UI + Ant Design 패턴)',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        story: 'Tailwind UI 알림 목록 패턴 + Ant Design 배지 카운트/일괄 액션 조합. 카테고리 탭 필터, 읽음/안읽음 토글, 개별 삭제, 모두 읽음 처리, Progress 바 진행률 포함.',
      },
    },
  },
  render: () => <NotiCenterRender />,
}

/* ==========================================================================
   Template #61 — OnboardingFlow (온보딩 플로우)
   Radix UI + Chakra UI 패턴: 단계별 진행, 역할 선택, 완료 화면
   ========================================================================== */
type OBRole = 'designer' | 'developer' | 'pm' | 'other'
type OBStep = 0 | 1 | 2 | 3

const OB_ROLES: { id: OBRole; label: string; desc: string; color: string; bg: string }[] = [
  { id: 'designer', label: 'Designer', desc: 'UI/UX 디자인 및 프로토타이핑', color: '#8b5cf6', bg: '#f5f3ff' },
  { id: 'developer', label: 'Developer', desc: '프론트엔드/백엔드 개발', color: '#3b82f6', bg: '#eff6ff' },
  { id: 'pm', label: 'Product Manager', desc: '제품 기획 및 로드맵 관리', color: '#10b981', bg: '#f0fdf4' },
  { id: 'other', label: 'Other', desc: '그 외 역할', color: '#64748b', bg: '#f8fafc' },
]

const OB_GOALS = ['더 빠른 UI 개발', '일관된 디자인 시스템', '팀 협업 효율화', '접근성 기준 충족', '다크모드 지원']

const OB_STEPS = ['환영', '역할 선택', '목표 설정', '완료']

const RadixOnboardingRender = () => {
  const [step, setStep] = React.useState<OBStep>(0)
  const [role, setRole] = React.useState<OBRole | null>(null)
  const [goals, setGoals] = React.useState<string[]>([])
  const [name, setName] = React.useState('')

  const toggleGoal = (g: string) => setGoals((prev) => prev.includes(g) ? prev.filter((x) => x !== g) : [...prev, g])

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #f0f7ff 0%, #faf5ff 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }}>
      <div style={{ width: '100%', maxWidth: 480, background: '#fff', borderRadius: 20, boxShadow: '0 8px 40px rgba(0,0,0,0.10)', overflow: 'hidden' }}>
        {/* 진행률 바 */}
        <div style={{ height: 4, background: '#f1f5f9' }}>
          <div style={{ height: '100%', width: `${((step) / 3) * 100}%`, background: 'linear-gradient(90deg, #6366f1, #8b5cf6)', transition: 'width 0.4s' }} />
        </div>

        {/* 단계 표시 */}
        <div style={{ display: 'flex', justifyContent: 'space-between', padding: '16px 24px 0', marginBottom: 8 }}>
          {OB_STEPS.map((s, i) => (
            <div key={s} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
              <div style={{ width: 24, height: 24, borderRadius: '50%', background: i <= step ? '#6366f1' : '#e2e8f0', color: i <= step ? '#fff' : '#94a3b8', fontSize: 11, fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'all 0.3s' }}>{i < step ? 'v' : i + 1}</div>
              <span style={{ fontSize: 11, color: i === step ? '#6366f1' : '#94a3b8', fontWeight: i === step ? 700 : 400, display: 'none' }}>{s}</span>
            </div>
          ))}
        </div>

        <div style={{ padding: '20px 32px 32px' }}>
          {/* Step 0: 환영 */}
          {step === 0 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
              <div style={{ textAlign: 'center', paddingTop: 8 }}>
                <div style={{ width: 64, height: 64, borderRadius: 16, background: 'linear-gradient(135deg, #6366f1, #8b5cf6)', margin: '0 auto 16px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 28 }}>{'<>'}</div>
                <h1 style={{ fontSize: 24, fontWeight: 800, color: '#0f172a', margin: '0 0 8px' }}>Orbit UI에 오신 것을 환영합니다</h1>
                <p style={{ fontSize: 14, color: '#64748b', lineHeight: 1.6, margin: 0 }}>빠르고 일관된 UI를 만드는 데 도움드리겠습니다. 몇 가지 질문에 답해주시면 최적의 환경을 세팅해 드립니다.</p>
              </div>
              <div>
                <label style={{ fontSize: 13, fontWeight: 600, color: '#374151', display: 'block', marginBottom: 8 }}>이름을 알려주세요</label>
                <TextField value={name} onChange={(e) => setName(e.target.value)} placeholder="홍길동" />
              </div>
              <SolidButton color="primary" size="large" disabled={!name} onClick={() => setStep(1)}>
                <SolidButton.Center>시작하기</SolidButton.Center>
              </SolidButton>
            </div>
          )}

          {/* Step 1: 역할 선택 */}
          {step === 1 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div>
                <h2 style={{ fontSize: 20, fontWeight: 800, color: '#0f172a', margin: '0 0 4px' }}>{name}님의 역할은 무엇인가요?</h2>
                <p style={{ fontSize: 13, color: '#64748b', margin: 0 }}>역할에 맞는 컴포넌트와 예시를 추천해 드립니다.</p>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {OB_ROLES.map((r) => (
                  <button key={r.id} onClick={() => setRole(r.id)} style={{ display: 'flex', alignItems: 'center', gap: 14, padding: '14px 16px', borderRadius: 12, border: `2px solid ${role === r.id ? r.color : '#e2e8f0'}`, background: role === r.id ? r.bg : '#fff', cursor: 'pointer', textAlign: 'left', transition: 'all 0.2s' }}>
                    <div style={{ width: 40, height: 40, borderRadius: 10, background: r.color, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 16, color: '#fff', fontWeight: 800, flexShrink: 0 }}>{r.label[0]}</div>
                    <div>
                      <div style={{ fontSize: 14, fontWeight: 700, color: '#0f172a' }}>{r.label}</div>
                      <div style={{ fontSize: 12, color: '#64748b' }}>{r.desc}</div>
                    </div>
                    {role === r.id && <span style={{ marginLeft: 'auto', color: r.color, fontWeight: 800, fontSize: 16 }}>v</span>}
                  </button>
                ))}
              </div>
              <div style={{ display: 'flex', gap: 8 }}>
                <OutlineButton color="black" size="large" onClick={() => setStep(0)} style={{ flex: 1 }}>
                  <OutlineButton.Center>이전</OutlineButton.Center>
                </OutlineButton>
                <SolidButton color="primary" size="large" disabled={!role} onClick={() => setStep(2)} style={{ flex: 1 }}>
                  <SolidButton.Center>다음</SolidButton.Center>
                </SolidButton>
              </div>
            </div>
          )}

          {/* Step 2: 목표 설정 */}
          {step === 2 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div>
                <h2 style={{ fontSize: 20, fontWeight: 800, color: '#0f172a', margin: '0 0 4px' }}>사용 목표를 선택해주세요</h2>
                <p style={{ fontSize: 13, color: '#64748b', margin: 0 }}>복수 선택 가능합니다.</p>
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {OB_GOALS.map((g) => {
                  const sel = goals.includes(g)
                  return (
                    <button key={g} onClick={() => toggleGoal(g)} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '12px 14px', borderRadius: 10, border: `1px solid ${sel ? '#6366f1' : '#e2e8f0'}`, background: sel ? '#eef2ff' : '#fff', cursor: 'pointer', textAlign: 'left', transition: 'all 0.2s', fontSize: 14, fontWeight: sel ? 600 : 400, color: '#0f172a' }}>
                      <span style={{ width: 20, height: 20, borderRadius: 5, border: `2px solid ${sel ? '#6366f1' : '#cbd5e1'}`, background: sel ? '#6366f1' : '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, fontSize: 11, color: '#fff', fontWeight: 800 }}>{sel ? 'v' : ''}</span>
                      {g}
                    </button>
                  )
                })}
              </div>
              <Progress value={Math.round((goals.length / OB_GOALS.length) * 100)} />
              <div style={{ fontSize: 12, color: '#64748b', textAlign: 'right' }}>{goals.length} / {OB_GOALS.length} 선택</div>
              <div style={{ display: 'flex', gap: 8 }}>
                <OutlineButton color="black" size="large" onClick={() => setStep(1)} style={{ flex: 1 }}>
                  <OutlineButton.Center>이전</OutlineButton.Center>
                </OutlineButton>
                <SolidButton color="primary" size="large" disabled={goals.length === 0} onClick={() => setStep(3)} style={{ flex: 1 }}>
                  <SolidButton.Center>완료</SolidButton.Center>
                </SolidButton>
              </div>
            </div>
          )}

          {/* Step 3: 완료 */}
          {step === 3 && (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 20, textAlign: 'center', paddingTop: 8 }}>
              <div style={{ width: 72, height: 72, borderRadius: '50%', background: '#dcfce7', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 32 }}>{'ok'}</div>
              <div>
                <h2 style={{ fontSize: 22, fontWeight: 800, color: '#0f172a', margin: '0 0 8px' }}>모든 설정 완료!</h2>
                <p style={{ fontSize: 14, color: '#64748b', lineHeight: 1.6, margin: 0 }}>
                  <b>{name}</b>님, 환영합니다.<br />
                  역할: <b>{OB_ROLES.find((r) => r.id === role)?.label}</b><br />
                  목표 {goals.length}개 선택됨
                </p>
              </div>
              <SegmentedControl defaultValue="light">
                <SegmentedControl.Tab value="light"><SegmentedControl.TabCenter>라이트 모드</SegmentedControl.TabCenter></SegmentedControl.Tab>
                <SegmentedControl.Tab value="dark"><SegmentedControl.TabCenter>다크 모드</SegmentedControl.TabCenter></SegmentedControl.Tab>
                <SegmentedControl.Tab value="system"><SegmentedControl.TabCenter>시스템</SegmentedControl.TabCenter></SegmentedControl.Tab>
              </SegmentedControl>
              <SolidButton color="primary" size="large" onClick={() => { setStep(0); setRole(null); setGoals([]); setName('') }} style={{ width: '100%' }}>
                <SolidButton.Center>대시보드로 이동</SolidButton.Center>
              </SolidButton>
              <GhostButton color="black" size="small" onClick={() => setStep(0)}>
                <GhostButton.Center>처음부터 다시</GhostButton.Center>
              </GhostButton>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

export const RadixChakraOnboarding: Story = {
  name: '온보딩 플로우 (Radix UI + Chakra UI 패턴)',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        story: 'Radix UI 단계 관리 + Chakra UI 단순 props 패턴 조합. 4단계 온보딩: 이름 입력 → 역할 선택 → 목표 설정(복수 선택) → 완료. Progress 바, SegmentedControl 테마 설정 포함.',
      },
    },
  },
  render: () => <RadixOnboardingRender />,
}

/* ==========================================================================
   Template #62 — TeamSettings (팀 설정 대시보드)
   MUI + Figma Plugin UI 패턴: Switch 그룹, CounterBadge, 멤버 관리
   ========================================================================== */
type TSRole = 'owner' | 'admin' | 'member' | 'viewer'
type TSMember = {
  id: string
  name: string
  email: string
  role: TSRole
  initials: string
  color: string
  lastActive: string
  notificationsOn: boolean
}

const TEAM_ROLE_CFG: Record<TSRole, { label: string; color: string; bg: string }> = {
  owner:  { label: 'Owner',  color: '#7c3aed', bg: '#f5f3ff' },
  admin:  { label: 'Admin',  color: '#dc2626', bg: '#fef2f2' },
  member: { label: 'Member', color: '#0369a1', bg: '#eff6ff' },
  viewer: { label: 'Viewer', color: '#64748b', bg: '#f8fafc' },
}

const INITIAL_MEMBERS: TSMember[] = [
  { id: 'm1', name: '김지훈', email: 'jihoon@orbit.dev', role: 'owner', initials: 'KJ', color: '#6366f1', lastActive: '방금', notificationsOn: true },
  { id: 'm2', name: '이수연', email: 'suyeon@orbit.dev', role: 'admin', initials: 'LS', color: '#ec4899', lastActive: '5분 전', notificationsOn: true },
  { id: 'm3', name: '박민준', email: 'minjun@orbit.dev', role: 'member', initials: 'PM', color: '#10b981', lastActive: '1시간 전', notificationsOn: false },
  { id: 'm4', name: '최아름', email: 'areum@orbit.dev', role: 'member', initials: 'CA', color: '#f59e0b', lastActive: '어제', notificationsOn: true },
  { id: 'm5', name: '정도윤', email: 'doyun@orbit.dev', role: 'viewer', initials: 'JD', color: '#64748b', lastActive: '3일 전', notificationsOn: false },
]

const SETTING_GROUPS = [
  {
    title: '알림 설정',
    settings: [
      { id: 'ts-email', label: '이메일 알림', desc: '멤버 초대, 댓글, 변경 사항 알림', default: true },
      { id: 'ts-push', label: '푸시 알림', desc: '실시간 모바일 알림', default: true },
      { id: 'ts-digest', label: '주간 요약', desc: '매주 팀 활동 요약 리포트', default: false },
    ],
  },
  {
    title: '접근 권한',
    settings: [
      { id: 'ts-public', label: '공개 링크 접근', desc: '링크가 있는 누구나 열람 가능', default: false },
      { id: 'ts-export', label: '데이터 내보내기', desc: 'CSV, JSON 형태로 데이터 다운로드', default: true },
      { id: 'ts-api', label: 'API 접근 허용', desc: '외부 앱에서 API 키로 접근', default: false },
    ],
  },
]

const TeamSettingsRender = () => {
  const [members, setMembers] = React.useState<TSMember[]>(INITIAL_MEMBERS)
  const [settingStates, setSettingStates] = React.useState<Record<string, boolean>>(
    Object.fromEntries(SETTING_GROUPS.flatMap((g) => g.settings.map((s) => [s.id, s.default])))
  )
  const [activeTab, setActiveTab] = React.useState<'members' | 'settings'>('members')
  const [search, setSearch] = React.useState('')

  const toggleSetting = (id: string) => setSettingStates((prev) => ({ ...prev, [id]: !prev[id] }))
  const toggleNotification = (id: string) => setMembers((prev) => prev.map((m) => m.id === id ? { ...m, notificationsOn: !m.notificationsOn } : m))

  const filteredMembers = members.filter((m) =>
    m.name.includes(search) || m.email.includes(search)
  )

  const roleCounts = (['owner', 'admin', 'member', 'viewer'] as TSRole[]).reduce<Record<string, number>>(
    (acc, r) => ({ ...acc, [r]: members.filter((m) => m.role === r).length }), {}
  )

  return (
    <div style={{ minHeight: '100vh', background: '#f8fafc', padding: 24 }}>
      <div style={{ maxWidth: 800, margin: '0 auto' }}>
        {/* 헤더 */}
        <div style={{ marginBottom: 24 }}>
          <h1 style={{ fontSize: 22, fontWeight: 800, color: '#0f172a', margin: '0 0 4px' }}>팀 설정</h1>
          <p style={{ fontSize: 14, color: '#64748b', margin: 0 }}>멤버 관리, 알림 설정, 접근 권한을 관리하세요.</p>
        </div>

        {/* 탭 */}
        <div style={{ display: 'flex', gap: 4, marginBottom: 20, background: '#fff', borderRadius: 10, padding: 4, border: '1px solid #e2e8f0', width: 'fit-content' }}>
          {(['members', 'settings'] as const).map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab)} style={{ padding: '8px 20px', borderRadius: 7, border: 'none', cursor: 'pointer', fontSize: 13, fontWeight: activeTab === tab ? 700 : 400, background: activeTab === tab ? '#0f172a' : 'transparent', color: activeTab === tab ? '#fff' : '#64748b', display: 'flex', alignItems: 'center', gap: 6, transition: 'all 0.2s' }}>
              {tab === 'members' ? '멤버' : '설정'}
              {tab === 'members' && <CounterBadge>{members.length}</CounterBadge>}
            </button>
          ))}
        </div>

        {/* 멤버 탭 */}
        {activeTab === 'members' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            {/* 역할별 카운트 배지 */}
            <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
              {(['owner', 'admin', 'member', 'viewer'] as TSRole[]).map((role) => {
                const cfg = TEAM_ROLE_CFG[role]
                return (
                  <div key={role} style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '6px 12px', borderRadius: 8, background: cfg.bg, border: `1px solid ${cfg.color}22` }}>
                    <span style={{ fontSize: 12, fontWeight: 600, color: cfg.color }}>{cfg.label}</span>
                    <CounterBadge>{roleCounts[role]}</CounterBadge>
                  </div>
                )
              })}
            </div>

            {/* 검색 */}
            <TextField value={search} onChange={(e) => setSearch(e.target.value)} placeholder="이름 또는 이메일로 검색..." />

            {/* 멤버 목록 */}
            <div style={{ background: '#fff', borderRadius: 12, border: '1px solid #e2e8f0', overflow: 'hidden' }}>
              {filteredMembers.map((member, i) => {
                const cfg = TEAM_ROLE_CFG[member.role]
                return (
                  <div key={member.id} style={{ display: 'flex', alignItems: 'center', gap: 14, padding: '14px 20px', borderBottom: i < filteredMembers.length - 1 ? '1px solid #f1f5f9' : 'none' }}>
                    <div style={{ width: 40, height: 40, borderRadius: '50%', background: member.color, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 13, fontWeight: 800, color: '#fff', flexShrink: 0 }}>
                      {member.initials}
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontSize: 14, fontWeight: 600, color: '#0f172a' }}>{member.name}</div>
                      <div style={{ fontSize: 12, color: '#64748b' }}>{member.email}</div>
                    </div>
                    <span style={{ fontSize: 11, fontWeight: 700, padding: '3px 8px', borderRadius: 6, background: cfg.bg, color: cfg.color, flexShrink: 0 }}>{cfg.label}</span>
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2, flexShrink: 0 }}>
                      <Switch
                        id={`notif-${member.id}`}
                        checked={member.notificationsOn}
                        onCheckedChange={() => toggleNotification(member.id)}
                      />
                      <span style={{ fontSize: 10, color: '#94a3b8' }}>알림</span>
                    </div>
                    <span style={{ fontSize: 11, color: '#94a3b8', flexShrink: 0 }}>{member.lastActive}</span>
                  </div>
                )
              })}
              {filteredMembers.length === 0 && (
                <div style={{ padding: '32px 20px', textAlign: 'center', color: '#94a3b8', fontSize: 14 }}>
                  검색 결과가 없습니다
                </div>
              )}
            </div>
          </div>
        )}

        {/* 설정 탭 */}
        {activeTab === 'settings' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            {SETTING_GROUPS.map((group) => (
              <div key={group.title} style={{ background: '#fff', borderRadius: 12, border: '1px solid #e2e8f0', overflow: 'hidden' }}>
                <div style={{ padding: '14px 20px', borderBottom: '1px solid #f1f5f9', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                  <span style={{ fontSize: 14, fontWeight: 700, color: '#0f172a' }}>{group.title}</span>
                  <CounterBadge>{group.settings.filter((s) => settingStates[s.id]).length}</CounterBadge>
                </div>
                {group.settings.map((setting, i) => (
                  <div key={setting.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '14px 20px', borderBottom: i < group.settings.length - 1 ? '1px solid #f1f5f9' : 'none' }}>
                    <div>
                      <div style={{ fontSize: 14, fontWeight: 600, color: '#0f172a', marginBottom: 2 }}>{setting.label}</div>
                      <div style={{ fontSize: 12, color: '#64748b' }}>{setting.desc}</div>
                    </div>
                    <Switch
                      id={setting.id}
                      checked={settingStates[setting.id]}
                      onCheckedChange={() => toggleSetting(setting.id)}
                    />
                  </div>
                ))}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

export const TeamSettings: Story = {
  name: '팀 설정 대시보드 (MUI + Figma Plugin UI 패턴)',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        story: 'MUI FormControlLabel Switch 그룹 + CounterBadge 탭/역할 카운트 + Figma 컴팩트 레이아웃 패턴. 멤버별 알림 토글, 역할 배지, 설정 그룹 활성 카운트, 검색 필터 포함.',
      },
    },
  },
  render: () => <TeamSettingsRender />,
}

