/* =====================================================================
   Mantine 벤치마크 — Team Onboarding Wizard (Cycle 91)
   Mantine의 Stepper + Form + Checkbox + Progress 패턴
   TextField, PasswordField, CheckboxWithLabel, Progress, SolidButton, Chip 통합
   ===================================================================== */

const MANTINE91_STEPS = ['계정 정보', '팀 설정', '알림 설정', '완료'] as const
type Mantine91Step = 0 | 1 | 2 | 3

const MANTINE91_ROLES = ['개발자', '디자이너', '프로덕트 매니저', '마케터', '기타'] as const

const MANTINE91_NOTIF_ITEMS = [
  { id: 'pr', label: 'Pull Request 알림', desc: '새 PR 생성 및 리뷰 요청' },
  { id: 'deploy', label: '배포 완료 알림', desc: '스테이징/프로덕션 배포 결과' },
  { id: 'mention', label: '멘션 알림', desc: '댓글에서 내가 언급될 때' },
  { id: 'weekly', label: '주간 요약 리포트', desc: '매주 월요일 팀 활동 요약' },
]

const Mantine91OnboardingRender = () => {
  const [step, setStep] = React.useState<Mantine91Step>(0)
  const [accountForm, setAccountForm] = React.useState({ name: '', email: '', password: '' })
  const [teamForm, setTeamForm] = React.useState({ teamName: '', role: '' as string, size: '' })
  const [notifications, setNotifications] = React.useState<Set<string>>(new Set(['pr', 'deploy']))
  const [touched, setTouched] = React.useState<Set<string>>(new Set())

  const touch = (field: string) => setTouched((prev) => new Set([...prev, field]))

  const accountErrors = {
    name: touched.has('name') && !accountForm.name.trim() ? '이름을 입력하세요' : null,
    email: touched.has('email') && !accountForm.email.includes('@') ? '올바른 이메일을 입력하세요' : null,
    password: touched.has('password') && accountForm.password.length < 8 ? '8자 이상 입력하세요' : null,
  }

  const step0Valid = !!accountForm.name.trim() && accountForm.email.includes('@') && accountForm.password.length >= 8
  const step1Valid = !!teamForm.teamName.trim() && !!teamForm.role

  const toggleNotif = (id: string) => {
    setNotifications((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const goNext = () => {
    if (step === 0) {
      setTouched(new Set(['name', 'email', 'password']))
      if (!step0Valid) return
    }
    if (step === 1) {
      if (!step1Valid) return
    }
    setStep((prev) => Math.min(3, prev + 1) as Mantine91Step)
  }

  const goPrev = () => setStep((prev) => Math.max(0, prev - 1) as Mantine91Step)

  const progressValue = (step / (MANTINE91_STEPS.length - 1)) * 100

  return (
    <div style={{ minHeight: '100vh', background: 'var(--sem-eclipse-color-backgroundSecondary)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }}>
      <div style={{ width: '100%', maxWidth: 560, background: 'var(--sem-eclipse-color-backgroundPrimary)', borderRadius: 20, border: '1px solid var(--sem-eclipse-color-borderSubtle)', overflow: 'hidden', boxShadow: '0 8px 32px rgba(0,0,0,0.08)' }}>
        {/* Header + Progress */}
        <div style={{ padding: '24px 28px 0' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
            <div style={{ fontSize: 18, fontWeight: 800, color: 'var(--sem-eclipse-color-foregroundPrimary)' }}>팀 온보딩</div>
            <span style={{ fontSize: 12, color: 'var(--sem-eclipse-color-foregroundTertiary)' }}>{step + 1} / {MANTINE91_STEPS.length}</span>
          </div>

          {/* Step pills */}
          <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
            {MANTINE91_STEPS.map((label, i) => (
              <div key={label} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4 }}>
                <div style={{
                  width: 28, height: 28, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center',
                  background: i < step ? '#10b981' : i === step ? '#6366f1' : 'var(--sem-eclipse-color-backgroundSecondary)',
                  border: `2px solid ${i <= step ? (i < step ? '#10b981' : '#6366f1') : 'var(--sem-eclipse-color-borderDefault)'}`,
                  fontSize: 11, fontWeight: 700,
                  color: i <= step ? '#fff' : 'var(--sem-eclipse-color-foregroundTertiary)',
                  transition: 'all 0.2s',
                }}>
                  {i < step ? '✓' : i + 1}
                </div>
                <span style={{ fontSize: 10, color: i === step ? '#6366f1' : 'var(--sem-eclipse-color-foregroundTertiary)', fontWeight: i === step ? 700 : 400, textAlign: 'center', lineHeight: 1.2 }}>{label}</span>
              </div>
            ))}
          </div>

          <Progress value={progressValue} />
        </div>

        {/* Step Content */}
        <div style={{ padding: '24px 28px' }}>
          {step === 0 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div style={{ fontSize: 15, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundPrimary)', marginBottom: 4 }}>계정 정보 입력</div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundSecondary)' }}>이름 *</label>
                <TextField
                  placeholder="홍길동"
                  value={accountForm.name}
                  onChange={(e) => { setAccountForm((p) => ({ ...p, name: e.target.value })); touch('name') }}
                  onBlur={() => touch('name')}
                />
                {accountErrors.name && <div style={{ fontSize: 11, color: '#ef4444' }}>{accountErrors.name}</div>}
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundSecondary)' }}>이메일 *</label>
                <TextField
                  placeholder="hong@example.com"
                  value={accountForm.email}
                  onChange={(e) => { setAccountForm((p) => ({ ...p, email: e.target.value })); touch('email') }}
                  onBlur={() => touch('email')}
                />
                {accountErrors.email && <div style={{ fontSize: 11, color: '#ef4444' }}>{accountErrors.email}</div>}
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundSecondary)' }}>비밀번호 *</label>
                <PasswordField
                  placeholder="8자 이상"
                  value={accountForm.password}
                  onChange={(e) => { setAccountForm((p) => ({ ...p, password: e.target.value })); touch('password') }}
                  onBlur={() => touch('password')}
                />
                {accountErrors.password && <div style={{ fontSize: 11, color: '#ef4444' }}>{accountErrors.password}</div>}
              </div>
            </div>
          )}

          {step === 1 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div style={{ fontSize: 15, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundPrimary)', marginBottom: 4 }}>팀 정보 설정</div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundSecondary)' }}>팀 이름 *</label>
                <TextField
                  placeholder="예: Orbit Dev Team"
                  value={teamForm.teamName}
                  onChange={(e) => setTeamForm((p) => ({ ...p, teamName: e.target.value }))}
                />
              </div>
              <div>
                <label style={{ fontSize: 12, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundSecondary)', marginBottom: 8, display: 'block' }}>역할 *</label>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                  {MANTINE91_ROLES.map((role) => (
                    <button
                      key={role}
                      onClick={() => setTeamForm((p) => ({ ...p, role }))}
                      style={{
                        padding: '6px 14px',
                        borderRadius: 20,
                        border: `2px solid ${teamForm.role === role ? '#6366f1' : 'var(--sem-eclipse-color-borderDefault)'}`,
                        background: teamForm.role === role ? '#eef2ff' : 'var(--sem-eclipse-color-backgroundPrimary)',
                        color: teamForm.role === role ? '#6366f1' : 'var(--sem-eclipse-color-foregroundSecondary)',
                        cursor: 'pointer',
                        fontWeight: teamForm.role === role ? 700 : 400,
                        fontSize: 13,
                        transition: 'all 0.12s',
                      }}
                    >
                      {role}
                    </button>
                  ))}
                </div>
                {!teamForm.role && <div style={{ fontSize: 11, color: '#94a3b8', marginTop: 6 }}>역할을 선택하세요</div>}
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundSecondary)' }}>팀 규모 (선택)</label>
                <TextField
                  placeholder="예: 5"
                  value={teamForm.size}
                  onChange={(e) => setTeamForm((p) => ({ ...p, size: e.target.value }))}
                />
              </div>
            </div>
          )}

          {step === 2 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div style={{ fontSize: 15, fontWeight: 700, color: 'var(--sem-eclipse-color-foregroundPrimary)', marginBottom: 4 }}>알림 수신 설정</div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {MANTINE91_NOTIF_ITEMS.map((item) => (
                  <div
                    key={item.id}
                    onClick={() => toggleNotif(item.id)}
                    style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 14px', borderRadius: 10, border: `1.5px solid ${notifications.has(item.id) ? '#6366f1' : 'var(--sem-eclipse-color-borderDefault)'}`, background: notifications.has(item.id) ? 'rgba(99,102,241,0.04)' : 'var(--sem-eclipse-color-backgroundPrimary)', cursor: 'pointer', transition: 'all 0.12s' }}
                  >
                    <CheckboxWithLabel
                      value={item.id}
                      checked={notifications.has(item.id)}
                      onChange={() => toggleNotif(item.id)}
                      onClick={(e) => e.stopPropagation()}
                    />
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--sem-eclipse-color-foregroundPrimary)' }}>{item.label}</div>
                      <div style={{ fontSize: 11, color: 'var(--sem-eclipse-color-foregroundTertiary)' }}>{item.desc}</div>
                    </div>
                  </div>
                ))}
              </div>
              <div style={{ fontSize: 11, color: 'var(--sem-eclipse-color-foregroundTertiary)' }}>
                {notifications.size}개 알림 선택됨 · 언제든지 설정에서 변경 가능합니다
              </div>
            </div>
          )}

          {step === 3 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16, alignItems: 'center', textAlign: 'center', padding: '16px 0' }}>
              <div style={{ width: 64, height: 64, borderRadius: '50%', background: '#f0fdf4', border: '3px solid #bbf7d0', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 28 }}>✓</div>
              <div>
                <div style={{ fontSize: 20, fontWeight: 800, color: 'var(--sem-eclipse-color-foregroundPrimary)', marginBottom: 8 }}>
                  환영합니다, {accountForm.name || '사용자'}님!
                </div>
                <div style={{ fontSize: 13, color: 'var(--sem-eclipse-color-foregroundSecondary)', lineHeight: 1.6 }}>
                  {teamForm.teamName && <span><strong>{teamForm.teamName}</strong> 팀으로 </span>}
                  온보딩이 완료됐습니다.
                  <br />{notifications.size}개 알림이 설정되었습니다.
                </div>
              </div>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', justifyContent: 'center' }}>
                {[accountForm.email, teamForm.role, `알림 ${notifications.size}개`].filter(Boolean).map((tag) => (
                  <span key={tag} style={{ padding: '4px 12px', borderRadius: 16, fontSize: 12, fontWeight: 700, background: '#eef2ff', border: '1.5px solid rgba(99,102,241,0.3)', color: '#6366f1' }}>
                    {tag}
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Footer Navigation */}
        <div style={{ padding: '0 28px 28px', display: 'flex', justifyContent: 'space-between', gap: 12 }}>
          {step > 0 && step < 3 ? (
            <SolidButton color="gray" size="medium" onClick={goPrev}>
              <SolidButton.Center>이전</SolidButton.Center>
            </SolidButton>
          ) : <div />}
          {step < 3 ? (
            <SolidButton color="primary" size="medium" onClick={goNext}>
              <SolidButton.Center>{step === 2 ? '완료' : '다음'}</SolidButton.Center>
            </SolidButton>
          ) : (
            <SolidButton color="primary" size="medium" onClick={() => { setStep(0); setAccountForm({ name: '', email: '', password: '' }); setTeamForm({ teamName: '', role: '', size: '' }); setNotifications(new Set(['pr', 'deploy'])); setTouched(new Set()) }}>
              <SolidButton.Center>처음부터</SolidButton.Center>
            </SolidButton>
          )}
        </div>
      </div>
    </div>
  )
}

export const MantineOnboardingWizard: Story = {
  name: 'Mantine — Team Onboarding Wizard',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        story:
          'Mantine Stepper + Form + Checkbox 패턴. 계정 정보 → 팀 설정 → 알림 설정 3단계 온보딩 위저드. ' +
          'TextField, PasswordField, CheckboxWithLabel, Progress, SolidButton, Chip 통합. ' +
          '각 단계에서 유효성 검사 후 다음 단계로 진행합니다.',
      },
    },
  },
  render: () => <Mantine91OnboardingRender />,
}

/* =====================================================================
   Radix UI 벤치마크 — Social Feed (Cycle 92)
   Radix UI의 Avatar, Badge, Separator, ScrollArea 패턴 반영
   AnimatedBadge, Avatar, LabelBadge, CounterBadge, ScrollableTabGroup,
   SpeechBadge, Divider, SolidButton, OutlineButton, Toggle 통합
   ===================================================================== */

const RADIX92_FEED_TABS = ['전체', '팔로잉', '트렌딩', '추천'] as const
type Radix92FeedTab = typeof RADIX92_FEED_TABS[number]

type Radix92Post = {
  id: number
  author: string
  initials: string
  role: string
  time: string
  content: string
  tags: string[]
  likes: number
  comments: number
  isNew: boolean
  isTrending: boolean
}

const RADIX92_POSTS: Radix92Post[] = [
  {
    id: 1, author: '김희준', initials: 'HJ', role: 'Design Systems', time: '방금', isNew: true, isTrending: true,
    content: 'Orbit UI 3.0 릴리스! 3단계 토큰 시스템과 Eclipse 테마가 드디어 공개됩니다. Radix Primitives 기반의 접근성과 vanilla-extract CSS-in-JS가 만났습니다.',
    tags: ['OrbitUI', 'DesignSystem', 'React'],
    likes: 142, comments: 23,
  },
  {
    id: 2, author: '이서연', initials: 'SY', role: 'Frontend Eng', time: '3분 전', isNew: false, isTrending: true,
    content: 'shadcn/ui의 Copy-paste 철학이 디자인 시스템 업계를 바꾸고 있습니다. 번들 크기 제로, 완전한 커스터마이징 — 이게 바로 미래입니다.',
    tags: ['shadcn', 'Frontend'],
    likes: 89, comments: 14,
  },
  {
    id: 3, author: '박지호', initials: 'JH', role: 'Product Design', time: '15분 전', isNew: false, isTrending: false,
    content: 'Figma Variables → CSS Custom Properties 동기화 워크플로우를 구축했습니다. 디자이너가 토큰을 업데이트하면 코드에 자동으로 반영됩니다.',
    tags: ['Figma', 'DesignToken', 'Automation'],
    likes: 67, comments: 9,
  },
  {
    id: 4, author: '최은아', initials: 'EA', role: 'Accessibility Eng', time: '1시간 전', isNew: false, isTrending: false,
    content: 'WCAG 2.2 업데이트에서 가장 중요한 변경: 2.4.11 Focus Appearance. 포커스 링의 최소 면적과 대비비 요구사항이 강화됩니다.',
    tags: ['A11y', 'WCAG', 'WebDev'],
    likes: 203, comments: 41,
  },
  {
    id: 5, author: '황민준', initials: 'MJ', role: 'DevOps', time: '2시간 전', isNew: false, isTrending: false,
    content: 'pnpm workspaces + Turborepo로 모노레포 빌드 시간을 68% 단축했습니다. 캐싱 전략과 병렬 실행 설정을 공유합니다.',
    tags: ['pnpm', 'Turborepo', 'DevOps'],
    likes: 134, comments: 28,
  },
]

const Radix92SocialFeedRender = () => {
  const [activeTab, setActiveTab] = React.useState<Radix92FeedTab>('전체')
  const [liked, setLiked] = React.useState<Set<number>>(new Set())
  const [bookmarked, setBookmarked] = React.useState<Set<number>>(new Set())
  const [showCompose, setShowCompose] = React.useState(false)
  const [composeText, setComposeText] = React.useState('')
  const [onlyFollowing, setOnlyFollowing] = React.useState(false)

  const visiblePosts = RADIX92_POSTS.filter((p) => {
    if (activeTab === '트렌딩') return p.isTrending
    if (activeTab === '팔로잉') return ['HJ', 'SY'].includes(p.initials)
    if (activeTab === '추천') return p.likes > 100
    return true
  })

  const toggleLike = (id: number) => {
    setLiked((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const toggleBookmark = (id: number) => {
    setBookmarked((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  return (
    <div style={{ minHeight: '100vh', background: 'var(--sem-eclipse-color-backgroundSecondary)', display: 'flex', flexDirection: 'column' }}>
      {/* Header */}
      <AppBar>
        <AppBar.Leading>
          <span style={{ fontWeight: 900, fontSize: 16, color: 'var(--sem-eclipse-color-foregroundPrimary)' }}>Orbit Feed</span>
        </AppBar.Leading>
        <AppBar.Trailing>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <div style={{ position: 'relative' }}>
              <AnimatedBadge color="sale">{3}</AnimatedBadge>
            </div>
            <Avatar style={{ width: 32, height: 32, fontSize: 12 }}>
              <Avatar.Fallback>나</Avatar.Fallback>
            </Avatar>
          </div>
        </AppBar.Trailing>
      </AppBar>

      <div style={{ flex: 1, maxWidth: 680, margin: '0 auto', width: '100%', display: 'flex', flexDirection: 'column' }}>
        {/* Compose Area */}
        <div style={{ background: 'var(--sem-eclipse-color-backgroundPrimary)', borderBottom: '1px solid var(--sem-eclipse-color-borderSubtle)', padding: '16px 20px' }}>
          {showCompose ? (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              <div style={{ display: 'flex', gap: 10, alignItems: 'flex-start' }}>
                <Avatar style={{ width: 36, height: 36, fontSize: 13, flexShrink: 0 }}>
                  <Avatar.Fallback>나</Avatar.Fallback>
                </Avatar>
                <textarea
                  placeholder="무슨 생각을 하고 계신가요?"
                  value={composeText}
                  onChange={(e) => setComposeText(e.target.value)}
                  style={{ flex: 1, minHeight: 80, resize: 'none', padding: '10px 14px', borderRadius: 10, border: '1.5px solid var(--sem-eclipse-color-borderDefault)', fontSize: 14, color: 'var(--sem-eclipse-color-foregroundPrimary)', background: 'var(--sem-eclipse-color-backgroundPrimary)', outline: 'none', fontFamily: 'inherit' }}
                />
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: 12, color: composeText.length > 280 ? '#ef4444' : 'var(--sem-eclipse-color-foregroundTertiary)' }}>
                  {composeText.length}/280
                </span>
                <div style={{ display: 'flex', gap: 8 }}>
                  <OutlineButton color="black" size="small" onClick={() => { setShowCompose(false); setComposeText('') }}>
                    <OutlineButton.Center>취소</OutlineButton.Center>
                  </OutlineButton>
                  <SolidButton color="primary" size="small" disabled={!composeText.trim() || composeText.length > 280} onClick={() => { setShowCompose(false); setComposeText('') }}>
                    <SolidButton.Center>게시</SolidButton.Center>
                  </SolidButton>
                </div>
              </div>
            </div>
          ) : (
            <div onClick={() => setShowCompose(true)} style={{ display: 'flex', gap: 10, alignItems: 'center', cursor: 'text' }}>
              <Avatar style={{ width: 36, height: 36, fontSize: 13, flexShrink: 0 }}>
                <Avatar.Fallback>나</Avatar.Fallback>
              </Avatar>
              <div style={{ flex: 1, padding: '10px 14px', borderRadius: 20, border: '1.5px solid var(--sem-eclipse-color-borderDefault)', fontSize: 14, color: 'var(--sem-eclipse-color-foregroundTertiary)', background: 'var(--sem-eclipse-color-backgroundSecondary)' }}>
                무슨 생각을 하고 계신가요?
              </div>
            </div>
          )}
        </div>

        {/* Filter Bar */}
        <div style={{ background: 'var(--sem-eclipse-color-backgroundPrimary)', borderBottom: '1px solid var(--sem-eclipse-color-borderSubtle)', padding: '0 20px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <ScrollableTabGroup>
            {RADIX92_FEED_TABS.map((tab) => (
              <ScrollableTabGroup.Tab
                key={tab}
                selected={activeTab === tab}
                onClick={() => setActiveTab(tab)}
              >
                {tab}
                {tab === '트렌딩' && <CounterBadge>{2}</CounterBadge>}
              </ScrollableTabGroup.Tab>
            ))}
          </ScrollableTabGroup>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6, paddingLeft: 12, borderLeft: '1px solid var(--sem-eclipse-color-borderSubtle)' }}>
            <Toggle checked={onlyFollowing} onChange={() => setOnlyFollowing((v) => !v)} />
            <span style={{ fontSize: 12, color: 'var(--sem-eclipse-color-foregroundTertiary)', whiteSpace: 'nowrap' }}>팔로잉만</span>
          </div>
        </div>

        {/* Feed Posts */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 0 }}>
          {visiblePosts.length === 0 && (
            <div style={{ padding: '40px', textAlign: 'center', color: 'var(--sem-eclipse-color-foregroundTertiary)', fontSize: 14 }}>게시물이 없습니다.</div>
          )}
          {visiblePosts.map((post, i) => (
            <div key={post.id}>
              <div style={{ padding: '16px 20px', background: 'var(--sem-eclipse-color-backgroundPrimary)', display: 'flex', gap: 12 }}>
                {/* Avatar */}
                <div style={{ flexShrink: 0, position: 'relative' }}>
                  <Avatar style={{ width: 42, height: 42, fontSize: 14 }}>
                    <Avatar.Fallback>{post.initials}</Avatar.Fallback>
                  </Avatar>
                  {post.isNew && (
                    <div style={{ position: 'absolute', bottom: -2, right: -2 }}>
                      <AnimatedBadge color="club" />
                    </div>
                  )}
                </div>

                {/* Content */}
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 2, flexWrap: 'wrap' }}>
                    <span style={{ fontSize: 14, fontWeight: 800, color: 'var(--sem-eclipse-color-foregroundPrimary)' }}>{post.author}</span>
                    <LabelBadge color="gray"><LabelBadge.Label>{post.role}</LabelBadge.Label></LabelBadge>
                    {post.isTrending && <LabelBadge color="sale"><LabelBadge.Label>인기</LabelBadge.Label></LabelBadge>}
                    <span style={{ fontSize: 12, color: 'var(--sem-eclipse-color-foregroundTertiary)', marginLeft: 'auto' }}>{post.time}</span>
                  </div>

                  <p style={{ margin: '0 0 10px', fontSize: 14, color: 'var(--sem-eclipse-color-foregroundPrimary)', lineHeight: 1.6 }}>
                    {post.content}
                  </p>

                  {/* Tags */}
                  <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4, marginBottom: 12 }}>
                    {post.tags.map((tag) => (
                      <SpeechBadge key={tag}>#{tag}</SpeechBadge>
                    ))}
                  </div>

                  {/* Actions */}
                  <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
                    <button onClick={() => toggleLike(post.id)} style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'none', border: 'none', cursor: 'pointer', fontSize: 13, color: liked.has(post.id) ? '#ef4444' : 'var(--sem-eclipse-color-foregroundTertiary)', fontWeight: liked.has(post.id) ? 700 : 400, transition: 'color 0.15s' }}>
                      <span style={{ fontSize: 16 }}>{liked.has(post.id) ? '❤' : '♡'}</span>
                      {post.likes + (liked.has(post.id) ? 1 : 0)}
                    </button>
                    <button style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'none', border: 'none', cursor: 'pointer', fontSize: 13, color: 'var(--sem-eclipse-color-foregroundTertiary)' }}>
                      <span style={{ fontSize: 16 }}>💬</span>
                      {post.comments}
                    </button>
                    <button onClick={() => toggleBookmark(post.id)} style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'none', border: 'none', cursor: 'pointer', fontSize: 13, color: bookmarked.has(post.id) ? '#6366f1' : 'var(--sem-eclipse-color-foregroundTertiary)', marginLeft: 'auto', transition: 'color 0.15s' }}>
                      <span style={{ fontSize: 16 }}>{bookmarked.has(post.id) ? '🔖' : '📌'}</span>
                    </button>
                  </div>
                </div>
              </div>
              {i < visiblePosts.length - 1 && <Divider />}
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}

export const RadixSocialFeed: Story = {
  name: 'Radix UI — Social Feed',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        story:
          'Radix UI 벤치마크: Avatar + Badge + Separator + ScrollArea 패턴. ' +
          'AnimatedBadge(새 게시물 표시), Avatar(작성자), LabelBadge(역할/인기 태그), ' +
          'SpeechBadge(해시태그), ScrollableTabGroup(피드 필터), Toggle(팔로잉 필터) 통합.',
      },
    },
  },
  render: () => <Radix92SocialFeedRender />,
}

/* ==========================================================================
   Cycle 93 — shadcn/ui 벤치마크: Team Dashboard
   shadcn/ui의 DataTable + Command + Card 패턴
   멤버 관리 대시보드: 검색, 역할 필터, DataTable, Skeleton 로딩, Badge
   ========================================================================== */
type Shadcn93Role = '전체' | '관리자' | '디자이너' | '개발자' | '기획자'
type Shadcn93MemberStatus = 'active' | 'inactive' | 'invited'

interface Shadcn93Member {
  id: number
  name: string
  role: Shadcn93Role
  email: string
  status: Shadcn93MemberStatus
  joinedAt: string
  taskCount: number
}

const SHADCN93_MEMBERS: Shadcn93Member[] = [
  { id: 1, name: '김희준', role: '관리자', email: 'hjunkim@orbit.dev', status: 'active', joinedAt: '2024-01-10', taskCount: 24 },
  { id: 2, name: '이서연', role: '개발자', email: 'sylee@orbit.dev', status: 'active', joinedAt: '2024-02-14', taskCount: 18 },
  { id: 3, name: '박지호', role: '디자이너', email: 'jhpark@orbit.dev', status: 'active', joinedAt: '2024-03-08', taskCount: 31 },
  { id: 4, name: '최은아', role: '기획자', email: 'eachoi@orbit.dev', status: 'active', joinedAt: '2024-04-22', taskCount: 15 },
  { id: 5, name: '정민수', role: '개발자', email: 'msjung@orbit.dev', status: 'inactive', joinedAt: '2024-05-01', taskCount: 7 },
  { id: 6, name: '윤하늘', role: '디자이너', email: 'hnyoon@orbit.dev', status: 'invited', joinedAt: '2025-04-05', taskCount: 0 },
  { id: 7, name: '강다연', role: '개발자', email: 'dygang@orbit.dev', status: 'active', joinedAt: '2024-06-12', taskCount: 22 },
]

const SHADCN93_ROLE_FILTERS: Shadcn93Role[] = ['전체', '관리자', '개발자', '디자이너', '기획자']

const SHADCN93_STATUS_META: Record<Shadcn93MemberStatus, { label: string; color: string; bg: string }> = {
  active:   { label: '활성', color: '#10b981', bg: '#f0fdf4' },
  inactive: { label: '비활성', color: '#94a3b8', bg: '#f8fafc' },
  invited:  { label: '초대됨', color: '#f59e0b', bg: '#fffbeb' },
}

const SHADCN93_ROLE_COLOR: Record<string, string> = {
  '관리자': '#6366f1',
  '개발자': '#0ea5e9',
  '디자이너': '#ec4899',
  '기획자': '#f59e0b',
}

function Shadcn93TeamDashboardRender() {
  const [search, setSearch] = React.useState('')
  const [roleFilter, setRoleFilter] = React.useState<Shadcn93Role>('전체')
  const [loading, setLoading] = React.useState(false)
  const [sortKey, setSortKey] = React.useState<'name' | 'taskCount' | 'joinedAt'>('name')
  const [sortAsc, setSortAsc] = React.useState(true)
  const [selectedIds, setSelectedIds] = React.useState<Set<number>>(new Set())
  const [page, setPage] = React.useState(1)
  const PAGE_SIZE = 5

  const handleSort = (key: typeof sortKey) => {
    if (sortKey === key) setSortAsc((a) => !a)
    else { setSortKey(key); setSortAsc(true) }
  }

  const filtered = SHADCN93_MEMBERS
    .filter((m) => roleFilter === '전체' || m.role === roleFilter)
    .filter((m) => search === '' || m.name.includes(search) || m.email.includes(search))
    .sort((a, b) => {
      const v = sortKey === 'taskCount' ? (a.taskCount - b.taskCount) : a[sortKey].localeCompare(b[sortKey])
      return sortAsc ? v : -v
    })

  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE))
  const paged = filtered.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE)

  const allSelected = paged.length > 0 && paged.every((m) => selectedIds.has(m.id))
  const toggleAll = () => {
    setSelectedIds((prev) => {
      const next = new Set(prev)
      if (allSelected) paged.forEach((m) => next.delete(m.id))
      else paged.forEach((m) => next.add(m.id))
      return next
    })
  }

  const refresh = () => {
    setLoading(true)
    setTimeout(() => setLoading(false), 1400)
  }

  const SortIcon = ({ col }: { col: typeof sortKey }) => (
    <span style={{ marginLeft: 3, fontSize: 10, color: sortKey === col ? '#6366f1' : '#d1d5db' }}>
      {sortKey === col ? (sortAsc ? '▲' : '▼') : '⇅'}
    </span>
  )

  const stats = [
    { label: '전체 멤버', value: SHADCN93_MEMBERS.length, color: '#6366f1', bg: '#eef2ff' },
    { label: '활성', value: SHADCN93_MEMBERS.filter((m) => m.status === 'active').length, color: '#10b981', bg: '#f0fdf4' },
    { label: '총 태스크', value: SHADCN93_MEMBERS.reduce((s, m) => s + m.taskCount, 0), color: '#0ea5e9', bg: '#f0f9ff' },
    { label: '초대 대기', value: SHADCN93_MEMBERS.filter((m) => m.status === 'invited').length, color: '#f59e0b', bg: '#fffbeb' },
  ]

  return (
    <div style={{ minHeight: '100vh', background: '#f8fafc', fontFamily: 'system-ui, sans-serif', padding: 0 }}>
      {/* Header */}
      <div style={{ background: '#fff', borderBottom: '1px solid #e2e8f0', padding: '14px 32px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <div style={{ width: 28, height: 28, borderRadius: 6, background: '#6366f1', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <PeopleLineIcon size={14} color="#fff" />
          </div>
          <span style={{ fontSize: 15, fontWeight: 700, color: '#0f172a' }}>팀 대시보드</span>
          <LabelBadge color="benefit"><LabelBadge.Label>shadcn/ui 패턴</LabelBadge.Label></LabelBadge>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <SolidButton
            onClick={refresh}
            color="gray"
            size="small"
          >
            <SolidButton.Center>{loading ? '새로고침 중...' : '새로고침'}</SolidButton.Center>
          </SolidButton>
          <SolidButton color="black" size="small">
            <SolidButton.Center>+ 멤버 초대</SolidButton.Center>
          </SolidButton>
        </div>
      </div>

      <div style={{ padding: '24px 32px', maxWidth: 1100, margin: '0 auto' }}>
        {/* Stats row */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12, marginBottom: 24 }}>
          {stats.map((s) => (
            <div key={s.label} style={{ background: '#fff', border: '1px solid #e2e8f0', borderRadius: 12, padding: '16px 20px', display: 'flex', alignItems: 'center', gap: 14 }}>
              <div style={{ width: 42, height: 42, borderRadius: 10, background: s.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                <span style={{ fontSize: 18, fontWeight: 800, color: s.color }}>{s.value}</span>
              </div>
              <span style={{ fontSize: 12, fontWeight: 600, color: '#64748b' }}>{s.label}</span>
            </div>
          ))}
        </div>

        {/* Table card */}
        <div style={{ background: '#fff', border: '1px solid #e2e8f0', borderRadius: 14, overflow: 'hidden' }}>
          {/* Toolbar */}
          <div style={{ padding: '14px 20px', borderBottom: '1px solid #f1f5f9', display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap' }}>
            <div style={{ position: 'relative', flex: 1, minWidth: 180 }}>
              <SearchIcon size={14} color="#94a3b8" style={{ position: 'absolute', left: 10, top: '50%', transform: 'translateY(-50%)', pointerEvents: 'none' }} />
              <input
                value={search}
                onChange={(e) => { setSearch(e.target.value); setPage(1) }}
                placeholder="이름·이메일 검색..."
                style={{ width: '100%', padding: '7px 10px 7px 32px', borderRadius: 8, border: '1.5px solid #e2e8f0', fontSize: 12, color: '#0f172a', outline: 'none', boxSizing: 'border-box' }}
              />
            </div>
            <div style={{ display: 'flex', gap: 4 }}>
              {SHADCN93_ROLE_FILTERS.map((r) => (
                <button
                  key={r}
                  onClick={() => { setRoleFilter(r); setPage(1) }}
                  style={{ padding: '6px 12px', borderRadius: 8, border: `1.5px solid ${roleFilter === r ? '#6366f1' : '#e2e8f0'}`, background: roleFilter === r ? '#eef2ff' : '#fff', color: roleFilter === r ? '#6366f1' : '#64748b', fontSize: 12, fontWeight: 600, cursor: 'pointer', transition: 'all 0.15s' }}
                >
                  {r}
                </button>
              ))}
            </div>
            {selectedIds.size > 0 && (
              <div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: 8 }}>
                <LabelBadge color="sale"><LabelBadge.Label>{selectedIds.size}명 선택</LabelBadge.Label></LabelBadge>
                <button onClick={() => setSelectedIds(new Set())} style={{ fontSize: 11, color: '#94a3b8', background: 'none', border: 'none', cursor: 'pointer' }}>선택 해제</button>
              </div>
            )}
          </div>

          {/* Table */}
          {loading ? (
            <div style={{ padding: '32px', display: 'flex', flexDirection: 'column', gap: 14 }}>
              {Array.from({ length: 5 }).map((_, i) => (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                  <Skeleton height={16} width={16} style={{ borderRadius: 3, flexShrink: 0 }} />
                  <Skeleton height={32} width={32} style={{ borderRadius: '50%', flexShrink: 0 }} />
                  <Skeleton height={14} width="20%" style={{ borderRadius: 4 }} />
                  <Skeleton height={14} width="25%" style={{ borderRadius: 4 }} />
                  <Skeleton height={20} width={52} style={{ borderRadius: 10 }} />
                  <Skeleton height={20} width={48} style={{ borderRadius: 10 }} />
                  <Skeleton height={14} width="10%" style={{ borderRadius: 4, marginLeft: 'auto' }} />
                </div>
              ))}
            </div>
          ) : (
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
              <thead>
                <tr style={{ background: '#f8fafc' }}>
                  <th style={{ padding: '10px 20px', textAlign: 'left', width: 40 }}>
                    <input type="checkbox" checked={allSelected} onChange={toggleAll} style={{ cursor: 'pointer', accentColor: '#6366f1' }} />
                  </th>
                  <th style={{ padding: '10px 12px', textAlign: 'left', fontWeight: 700, color: '#475569', cursor: 'pointer' }} onClick={() => handleSort('name')}>
                    이름 <SortIcon col="name" />
                  </th>
                  <th style={{ padding: '10px 12px', textAlign: 'left', fontWeight: 700, color: '#475569' }}>역할</th>
                  <th style={{ padding: '10px 12px', textAlign: 'left', fontWeight: 700, color: '#475569' }}>상태</th>
                  <th style={{ padding: '10px 12px', textAlign: 'left', fontWeight: 700, color: '#475569', cursor: 'pointer' }} onClick={() => handleSort('joinedAt')}>
                    가입일 <SortIcon col="joinedAt" />
                  </th>
                  <th style={{ padding: '10px 20px', textAlign: 'right', fontWeight: 700, color: '#475569', cursor: 'pointer' }} onClick={() => handleSort('taskCount')}>
                    태스크 <SortIcon col="taskCount" />
                  </th>
                </tr>
              </thead>
              <tbody>
                {paged.length === 0 ? (
                  <tr>
                    <td colSpan={6} style={{ padding: '32px', textAlign: 'center', color: '#94a3b8', fontSize: 13 }}>
                      검색 결과가 없습니다
                    </td>
                  </tr>
                ) : (
                  paged.map((m) => {
                    const st = SHADCN93_STATUS_META[m.status]
                    const isSelected = selectedIds.has(m.id)
                    return (
                      <tr
                        key={m.id}
                        style={{ borderTop: '1px solid #f1f5f9', background: isSelected ? '#f8f8ff' : '#fff', transition: 'background 0.1s' }}
                      >
                        <td style={{ padding: '12px 20px' }}>
                          <input
                            type="checkbox"
                            checked={isSelected}
                            onChange={() => setSelectedIds((prev) => { const n = new Set(prev); if (isSelected) { n.delete(m.id) } else { n.add(m.id) } return n })}
                            style={{ cursor: 'pointer', accentColor: '#6366f1' }}
                          />
                        </td>
                        <td style={{ padding: '12px 12px' }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                            <div style={{ width: 32, height: 32, borderRadius: '50%', background: SHADCN93_ROLE_COLOR[m.role] ?? '#6366f1', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 12, fontWeight: 700, color: '#fff', flexShrink: 0 }}>
                              {m.name[0]}
                            </div>
                            <div>
                              <div style={{ fontWeight: 600, color: '#0f172a' }}>{m.name}</div>
                              <div style={{ fontSize: 11, color: '#94a3b8' }}>{m.email}</div>
                            </div>
                          </div>
                        </td>
                        <td style={{ padding: '12px 12px' }}>
                          <span style={{ padding: '2px 10px', borderRadius: 20, background: (SHADCN93_ROLE_COLOR[m.role] ?? '#6366f1') + '18', color: SHADCN93_ROLE_COLOR[m.role] ?? '#6366f1', fontSize: 11, fontWeight: 700 }}>{m.role}</span>
                        </td>
                        <td style={{ padding: '12px 12px' }}>
                          <span style={{ padding: '2px 10px', borderRadius: 20, background: st.bg, color: st.color, fontSize: 11, fontWeight: 700 }}>{st.label}</span>
                        </td>
                        <td style={{ padding: '12px 12px', color: '#64748b', fontSize: 12 }}>{m.joinedAt}</td>
                        <td style={{ padding: '12px 20px', textAlign: 'right', fontWeight: 700, color: m.taskCount > 20 ? '#6366f1' : '#334155' }}>{m.taskCount}</td>
                      </tr>
                    )
                  })
                )}
              </tbody>
            </table>
          )}

          {/* Pagination */}
          <div style={{ padding: '12px 20px', borderTop: '1px solid #f1f5f9', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <span style={{ fontSize: 12, color: '#94a3b8' }}>
              {filtered.length}명 중 {Math.min((page - 1) * PAGE_SIZE + 1, filtered.length)}-{Math.min(page * PAGE_SIZE, filtered.length)} 표시
            </span>
            <div style={{ display: 'flex', gap: 4 }}>
              <button
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page === 1}
                style={{ padding: '5px 12px', borderRadius: 7, border: '1px solid #e2e8f0', background: '#fff', fontSize: 12, fontWeight: 600, color: page === 1 ? '#d1d5db' : '#334155', cursor: page === 1 ? 'not-allowed' : 'pointer' }}
              >
                이전
              </button>
              {Array.from({ length: totalPages }, (_, i) => i + 1).map((p) => (
                <button
                  key={p}
                  onClick={() => setPage(p)}
                  style={{ padding: '5px 10px', borderRadius: 7, border: `1px solid ${page === p ? '#6366f1' : '#e2e8f0'}`, background: page === p ? '#eef2ff' : '#fff', fontSize: 12, fontWeight: page === p ? 700 : 400, color: page === p ? '#6366f1' : '#334155', cursor: 'pointer' }}
                >
                  {p}
                </button>
              ))}
              <button
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                style={{ padding: '5px 12px', borderRadius: 7, border: '1px solid #e2e8f0', background: '#fff', fontSize: 12, fontWeight: 600, color: page === totalPages ? '#d1d5db' : '#334155', cursor: page === totalPages ? 'not-allowed' : 'pointer' }}
              >
                다음
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

/* ==========================================================================
   Cycle 94 — Linear Design 벤치마크: Product Roadmap
   Linear의 Roadmap 뷰 — 분기별 마일스톤 + 프로젝트 진행률 + 이슈 Backlog
   Progress, LabelBadge, SectionTitle, Divider, ScrollableTabGroup 통합
   ========================================================================== */
type Linear94Quarter = 'Q1' | 'Q2' | 'Q3' | 'Q4'
