/* ==========================================================================
   Cycle 124 — Vercel Design + Radix UI 벤치마크
   템플릿: 개발자 설정 패널 (BoxedCheckbox + Chip + Accordion + 탭)
========================================================================== */

type EnvVar124 = { key: string; value: string; env: 'production' | 'preview' | 'development'; sensitive: boolean }

const ENV_VARS_124: EnvVar124[] = [
  { key: 'DATABASE_URL', value: 'postgresql://****', env: 'production', sensitive: true },
  { key: 'NEXTAUTH_SECRET', value: '****', env: 'production', sensitive: true },
  { key: 'API_BASE_URL', value: 'https://api.example.com', env: 'preview', sensitive: false },
  { key: 'SENTRY_DSN', value: 'https://****@sentry.io/123', env: 'production', sensitive: true },
  { key: 'FEATURE_DARK_MODE', value: 'true', env: 'development', sensitive: false },
  { key: 'DEBUG_LEVEL', value: 'verbose', env: 'development', sensitive: false },
  { key: 'REDIS_URL', value: 'redis://****', env: 'preview', sensitive: true },
  { key: 'STRIPE_KEY', value: 'sk_****', env: 'production', sensitive: true },
]

type BuildStep124 = 'lint' | 'typecheck' | 'test' | 'build' | 'e2e'
const BUILD_STEPS_124: { id: BuildStep124; label: string; desc: string; required: boolean }[] = [
  { id: 'lint', label: 'ESLint', desc: 'max-warnings 0', required: true },
  { id: 'typecheck', label: 'TypeScript', desc: 'tsc --noEmit', required: true },
  { id: 'test', label: 'Unit Tests', desc: 'vitest run --coverage', required: false },
  { id: 'build', label: 'Build', desc: 'vite build', required: true },
  { id: 'e2e', label: 'E2E Tests', desc: 'playwright test', required: false },
]

type NotifEvent124 = 'deploy_ok' | 'deploy_fail' | 'pr_open' | 'security'
const NOTIF_EVENTS_124: Record<NotifEvent124, string> = {
  deploy_ok: '배포 성공',
  deploy_fail: '배포 실패',
  pr_open: 'PR 오픈',
  security: '보안 알림',
}

function DevSettingsPanel124Render() {
  const [settingsTab, setSettingsTab] = useState<'env' | 'build' | 'notifications'>('env')
  const [envFilter, setEnvFilter] = useState<Set<string>>(new Set(['production', 'preview', 'development']))
  const [buildSteps, setBuildSteps] = useState<Set<BuildStep124>>(new Set(['lint', 'typecheck', 'build']))
  const [notifOn, setNotifOn] = useState<Set<NotifEvent124>>(new Set(['deploy_fail', 'security']))
  const [search, setSearch] = useState('')

  const toggleEnvFilter = (e: string) => {
    setEnvFilter((prev) => {
      const next = new Set(prev)
      if (next.has(e)) next.delete(e)
      else next.add(e)
      return next
    })
  }

  const toggleBuild = (id: BuildStep124, required: boolean) => {
    if (required) return
    setBuildSteps((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const toggleNotif = (ev: NotifEvent124) => {
    setNotifOn((prev) => {
      const next = new Set(prev)
      if (next.has(ev)) next.delete(ev)
      else next.add(ev)
      return next
    })
  }

  const filteredEnvVars = ENV_VARS_124.filter((v) =>
    envFilter.has(v.env) && v.key.toLowerCase().includes(search.toLowerCase())
  )

  const TABS: { id: 'env' | 'build' | 'notifications'; label: string }[] = [
    { id: 'env', label: '환경 변수' },
    { id: 'build', label: '빌드 설정' },
    { id: 'notifications', label: '알림' },
  ]

  return (
    <div style={{ width: 640, fontFamily: 'system-ui, sans-serif' }}>
      {/* Header */}
      <div style={{ marginBottom: 20 }}>
        <h2 style={{ margin: 0, fontSize: 22, fontWeight: 800, color: '#0f172a' }}>개발자 설정</h2>
        <p style={{ margin: '4px 0 0', fontSize: 13, color: '#64748b' }}>Vercel Design + Radix UI 벤치마크 — Cycle 124</p>
      </div>

      {/* Tab nav */}
      <div style={{ display: 'flex', borderBottom: '2px solid #e2e8f0', marginBottom: 24 }}>
        {TABS.map((t) => (
          <button
            key={t.id}
            onClick={() => setSettingsTab(t.id)}
            style={{
              padding: '10px 20px', border: 'none', background: 'none', cursor: 'pointer',
              fontSize: 14, fontWeight: settingsTab === t.id ? 700 : 500,
              color: settingsTab === t.id ? '#6366f1' : '#64748b',
              borderBottom: settingsTab === t.id ? '2px solid #6366f1' : '2px solid transparent',
              marginBottom: '-2px',
            }}
          >
            {t.label}
          </button>
        ))}
      </div>

      {/* ENV VARS tab */}
      {settingsTab === 'env' && (
        <div>
          <div style={{ display: 'flex', gap: 10, marginBottom: 14, alignItems: 'center', flexWrap: 'wrap' }}>
            <div style={{ flex: 1 }}>
              <TextField
                placeholder="변수명 검색..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
            </div>
            <div style={{ display: 'flex', gap: 6 }}>
              {(['production', 'preview', 'development'] as const).map((env) => (
                <Chip key={env} selected={envFilter.has(env)} onClick={() => toggleEnvFilter(env)}>
                  {env === 'production' ? '프로덕션' : env === 'preview' ? '프리뷰' : '개발'}
                </Chip>
              ))}
            </div>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
            {filteredEnvVars.map((v) => (
              <div key={v.key} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', borderRadius: 10, border: '1px solid #f1f5f9', background: '#fff' }}>
                <div style={{ flex: 1, fontFamily: 'monospace' }}>
                  <div style={{ fontSize: 13, fontWeight: 700, color: '#1e293b' }}>{v.key}</div>
                  <div style={{ fontSize: 12, color: '#94a3b8', marginTop: 2 }}>{v.sensitive ? '•'.repeat(12) : v.value}</div>
                </div>
                <LabelBadge color={v.env === 'production' ? 'sale' : 'gray'}>
                  <LabelBadge.Label>{v.env}</LabelBadge.Label>
                </LabelBadge>
                {v.sensitive && (
                  <LabelBadge color="gray">
                    <LabelBadge.Label>민감</LabelBadge.Label>
                  </LabelBadge>
                )}
              </div>
            ))}
            {filteredEnvVars.length === 0 && (
              <div style={{ padding: '32px 0', textAlign: 'center', color: '#94a3b8', fontSize: 14 }}>변수 없음</div>
            )}
          </div>
          <div style={{ marginTop: 14, display: 'flex', justifyContent: 'flex-end' }}>
            <SolidButton color="black" size="medium">
              <SolidButton.Center>변수 추가</SolidButton.Center>
            </SolidButton>
          </div>
        </div>
      )}

      {/* BUILD SETTINGS tab */}
      {settingsTab === 'build' && (
        <div>
          <div style={{ fontSize: 13, color: '#64748b', marginBottom: 16 }}>
            각 단계를 활성화하여 빌드 파이프라인을 구성하세요. 필수 단계는 비활성화할 수 없습니다.
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {BUILD_STEPS_124.map((step) => {
              const isOn = buildSteps.has(step.id)
              return (
                <div
                  key={step.id}
                  onClick={() => toggleBuild(step.id, step.required)}
                  style={{
                    display: 'flex', alignItems: 'center', gap: 14, padding: '14px 16px',
                    borderRadius: 12, cursor: step.required ? 'not-allowed' : 'pointer',
                    border: `1.5px solid ${isOn ? '#6366f1' : '#e2e8f0'}`,
                    background: isOn ? '#f0f0ff' : '#fff', transition: 'all 0.15s',
                  }}
                >
                  <BoxedCheckbox
                    checked={isOn}
                    disabled={step.required}
                    onChange={() => toggleBuild(step.id, step.required)}
                  />
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <span style={{ fontSize: 14, fontWeight: 700, color: '#1e293b' }}>{step.label}</span>
                      {step.required && <span style={{ fontSize: 11, padding: '1px 6px', borderRadius: 4, background: '#f1f5f9', color: '#64748b', fontWeight: 700 }}>필수</span>}
                    </div>
                    <div style={{ fontSize: 12, color: '#94a3b8', marginTop: 2, fontFamily: 'monospace' }}>{step.desc}</div>
                  </div>
                  <span style={{ fontSize: 12, fontWeight: 700, color: isOn ? '#6366f1' : '#cbd5e1' }}>{isOn ? '활성' : '비활성'}</span>
                </div>
              )
            })}
          </div>
          <div style={{ marginTop: 14, padding: '12px 16px', borderRadius: 10, background: '#f8fafc', border: '1px solid #e2e8f0', fontSize: 13, color: '#64748b' }}>
            {buildSteps.size}개 단계 활성화 · 예상 소요: ~{buildSteps.size * 45}초
          </div>
        </div>
      )}

      {/* NOTIFICATIONS tab */}
      {settingsTab === 'notifications' && (
        <div>
          <div style={{ fontSize: 13, color: '#64748b', marginBottom: 16 }}>수신할 알림 이벤트를 선택하세요.</div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {(Object.keys(NOTIF_EVENTS_124) as NotifEvent124[]).map((ev) => (
              <div
                key={ev}
                onClick={() => toggleNotif(ev)}
                style={{ display: 'flex', alignItems: 'center', gap: 14, padding: '14px 16px', borderRadius: 12, border: '1px solid #f1f5f9', background: '#fff', cursor: 'pointer' }}
              >
                <BoxedCheckbox checked={notifOn.has(ev)} onChange={() => toggleNotif(ev)} />
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 14, fontWeight: 600, color: '#1e293b' }}>{NOTIF_EVENTS_124[ev]}</div>
                </div>
                {ev === 'security' && (
                  <LabelBadge color="sale">
                    <LabelBadge.Label>권장</LabelBadge.Label>
                  </LabelBadge>
                )}
              </div>
            ))}
          </div>
          <div style={{ marginTop: 14, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontSize: 13, color: '#94a3b8' }}>{notifOn.size}개 이벤트 알림 활성</span>
            <SolidButton color="black" size="medium">
              <SolidButton.Center>저장</SolidButton.Center>
            </SolidButton>
          </div>
        </div>
      )}
    </div>
  )
}

export const VercelRadix124DevSettings: StoryObj = {
  name: 'Vercel + Radix UI — 개발자 설정 패널 (Cycle 124)',
  parameters: {
    layout: 'centered',
    docs: {
      description: {
        story:
          'Vercel Design + Radix UI 벤치마크 — Cycle 124. ' +
          'BoxedCheckbox 빌드 단계 선택 + Chip 환경 필터 + TextField 검색 + LabelBadge 상태 표시. ' +
          '환경변수/빌드/알림 3탭 개발자 설정 패널입니다.',
      },
    },
  },
  render: () => <DevSettingsPanel124Render />,
}

/* ==========================================================================
   Cycle 125 — MUI + Tailwind UI 벤치마크
   템플릿: 이슈 트래커 (Drawer 필터 + ChipLink 탐색 + DataTable 스타일)
========================================================================== */

type Issue125 = {
  id: string
  title: string
  status: 'open' | 'in_progress' | 'in_review' | 'done'
  priority: 'urgent' | 'high' | 'medium' | 'low'
  assignee: string
  label: string
  created: string
}

const ISSUES_125: Issue125[] = [
  { id: 'ENG-001', title: '로그인 폼 유효성 검사 개선', status: 'in_progress', priority: 'high', assignee: '김민준', label: 'Frontend', created: '2일 전' },
  { id: 'ENG-002', title: 'WebSocket 연결 안정화', status: 'open', priority: 'urgent', assignee: '이서연', label: 'Backend', created: '방금' },
  { id: 'ENG-003', title: '다크모드 CSS 변수 정리', status: 'in_review', priority: 'medium', assignee: '박준혁', label: 'Design', created: '5시간 전' },
  { id: 'ENG-004', title: 'E2E 테스트 커버리지 확장', status: 'open', priority: 'low', assignee: '최유진', label: 'QA', created: '3일 전' },
  { id: 'ENG-005', title: '번들 사이즈 최적화', status: 'done', priority: 'medium', assignee: '김민준', label: 'Frontend', created: '1주 전' },
  { id: 'ENG-006', title: '접근성 audit 반영', status: 'in_progress', priority: 'high', assignee: '이서연', label: 'Frontend', created: '1일 전' },
  { id: 'ENG-007', title: 'API rate limiting 구현', status: 'open', priority: 'high', assignee: '박준혁', label: 'Backend', created: '4시간 전' },
  { id: 'ENG-008', title: 'Storybook 8 업그레이드', status: 'done', priority: 'low', assignee: '최유진', label: 'DevOps', created: '2주 전' },
]

const ISSUE_STATUS_META: Record<Issue125['status'], { label: string; color: string; bg: string }> = {
  open: { label: 'Open', color: '#10b981', bg: '#f0fdf4' },
  in_progress: { label: 'In Progress', color: '#6366f1', bg: '#f0f0ff' },
  in_review: { label: 'In Review', color: '#f59e0b', bg: '#fffbeb' },
  done: { label: 'Done', color: '#94a3b8', bg: '#f1f5f9' },
}

const PRIORITY_COLOR_125: Record<Issue125['priority'], string> = {
  urgent: '#ef4444', high: '#f59e0b', medium: '#6366f1', low: '#94a3b8',
}

function IssueTracker125Render() {
  const [filterOpen, setFilterOpen] = useState(false)
  const [statusFilter, setStatusFilter] = useState<Set<Issue125['status']>>(new Set(['open', 'in_progress', 'in_review']))
  const [priorityFilter, setPriorityFilter] = useState<Set<Issue125['priority']>>(new Set())
  const [labelFilter, setLabelFilter] = useState<string | null>(null)
  const [search, setSearch] = useState('')

  const LABELS = Array.from(new Set(ISSUES_125.map((i) => i.label)))

  const toggleStatus = (s: Issue125['status']) => {
    setStatusFilter((prev) => { const n = new Set(prev); if (n.has(s)) n.delete(s); else n.add(s); return n })
  }
  const togglePriority = (p: Issue125['priority']) => {
    setPriorityFilter((prev) => { const n = new Set(prev); if (n.has(p)) n.delete(p); else n.add(p); return n })
  }

  const filtered = ISSUES_125.filter((issue) => {
    const matchStatus = statusFilter.size === 0 || statusFilter.has(issue.status)
    const matchPriority = priorityFilter.size === 0 || priorityFilter.has(issue.priority)
    const matchLabel = !labelFilter || issue.label === labelFilter
    const matchSearch = !search || issue.title.toLowerCase().includes(search.toLowerCase()) || issue.assignee.includes(search)
    return matchStatus && matchPriority && matchLabel && matchSearch
  })

  const totalFilters = statusFilter.size + priorityFilter.size + (labelFilter ? 1 : 0)

  return (
    <div style={{ width: 700, fontFamily: 'system-ui, sans-serif' }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 20 }}>
        <div>
          <h2 style={{ margin: 0, fontSize: 22, fontWeight: 800, color: '#0f172a' }}>이슈 트래커</h2>
          <p style={{ margin: '4px 0 0', fontSize: 13, color: '#64748b' }}>MUI + Tailwind UI 벤치마크 — Cycle 125</p>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          {(['open', 'in_progress', 'in_review', 'done'] as Issue125['status'][]).map((s) => {
            const meta = ISSUE_STATUS_META[s]
            return (
              <div key={s} style={{ padding: '6px 12px', borderRadius: 8, background: meta.bg, border: `1px solid ${meta.color}33` }}>
                <div style={{ fontSize: 18, fontWeight: 800, color: meta.color }}>{ISSUES_125.filter((i) => i.status === s).length}</div>
                <div style={{ fontSize: 10, color: meta.color, fontWeight: 600 }}>{meta.label}</div>
              </div>
            )
          })}
        </div>
      </div>

      {/* Toolbar */}
      <div style={{ display: 'flex', gap: 10, marginBottom: 14, alignItems: 'center' }}>
        <div style={{ flex: 1 }}>
          <TextField placeholder="이슈 또는 담당자 검색..." value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>

        {/* Label ChipLinks */}
        <div style={{ display: 'flex', gap: 6 }}>
          <button
            onClick={() => setLabelFilter(null)}
            style={{ padding: '6px 12px', borderRadius: 20, border: `1.5px solid ${!labelFilter ? '#6366f1' : '#e2e8f0'}`, background: !labelFilter ? '#6366f1' : '#fff', color: !labelFilter ? '#fff' : '#64748b', fontSize: 12, fontWeight: 600, cursor: 'pointer' }}
          >
            전체
          </button>
          {LABELS.map((label) => (
            <button
              key={label}
              onClick={() => setLabelFilter(labelFilter === label ? null : label)}
              style={{ padding: '6px 12px', borderRadius: 20, border: `1.5px solid ${labelFilter === label ? '#6366f1' : '#e2e8f0'}`, background: labelFilter === label ? '#f0f0ff' : '#fff', color: labelFilter === label ? '#6366f1' : '#64748b', fontSize: 12, fontWeight: 600, cursor: 'pointer' }}
            >
              {label}
            </button>
          ))}
        </div>

        {/* Drawer filter button */}
        <Drawer open={filterOpen} onOpenChange={setFilterOpen}>
          <Drawer.Trigger asChild>
            <OutlineButton color="black" size="medium">
              <OutlineButton.Center>
                필터 {totalFilters > 0 ? `(${totalFilters})` : ''}
              </OutlineButton.Center>
            </OutlineButton>
          </Drawer.Trigger>
          <Drawer.Content side="right">
            <Drawer.Header>
              <Drawer.Title>이슈 필터</Drawer.Title>
              <Drawer.Description>표시할 이슈 조건을 설정하세요.</Drawer.Description>
            </Drawer.Header>
            <div style={{ flex: 1, overflowY: 'auto', padding: '16px 20px', display: 'flex', flexDirection: 'column', gap: 20 }}>
              <div>
                <div style={{ fontSize: 12, fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 8 }}>상태</div>
                {(['open', 'in_progress', 'in_review', 'done'] as Issue125['status'][]).map((s) => {
                  const meta = ISSUE_STATUS_META[s]
                  return (
                    <label key={s} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '7px 0', cursor: 'pointer' }}>
                      <input type="checkbox" checked={statusFilter.has(s)} onChange={() => toggleStatus(s)} style={{ width: 16, height: 16, accentColor: '#6366f1' }} />
                      <span style={{ width: 8, height: 8, borderRadius: '50%', background: meta.color, flexShrink: 0 }} />
                      <span style={{ fontSize: 13, color: '#1e293b' }}>{meta.label}</span>
                    </label>
                  )
                })}
              </div>
              <div>
                <div style={{ fontSize: 12, fontWeight: 700, color: '#64748b', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 8 }}>우선순위</div>
                {(['urgent', 'high', 'medium', 'low'] as Issue125['priority'][]).map((p) => (
                  <label key={p} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '7px 0', cursor: 'pointer' }}>
                    <input type="checkbox" checked={priorityFilter.has(p)} onChange={() => togglePriority(p)} style={{ width: 16, height: 16, accentColor: '#6366f1' }} />
                    <span style={{ width: 8, height: 8, borderRadius: '50%', background: PRIORITY_COLOR_125[p], flexShrink: 0 }} />
                    <span style={{ fontSize: 13, color: '#1e293b', textTransform: 'capitalize' }}>{p}</span>
                  </label>
                ))}
              </div>
            </div>
            <Drawer.Footer>
              <OutlineButton color="black" size="medium" onClick={() => { setStatusFilter(new Set()); setPriorityFilter(new Set()) }}>
                <OutlineButton.Center>초기화</OutlineButton.Center>
              </OutlineButton>
              <SolidButton color="black" size="medium" onClick={() => setFilterOpen(false)}>
                <SolidButton.Center>적용</SolidButton.Center>
              </SolidButton>
            </Drawer.Footer>
          </Drawer.Content>
        </Drawer>
      </div>

      {/* Issue list */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        {filtered.length === 0 ? (
          <div style={{ padding: '40px 0', textAlign: 'center', color: '#94a3b8', fontSize: 14 }}>조건에 맞는 이슈가 없습니다.</div>
        ) : (
          filtered.map((issue) => {
            const statusMeta = ISSUE_STATUS_META[issue.status]
            return (
              <div key={issue.id} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', borderRadius: 12, border: '1px solid #f1f5f9', background: '#fff' }}>
                <span style={{ width: 8, height: 8, borderRadius: '50%', background: PRIORITY_COLOR_125[issue.priority], flexShrink: 0 }} />
                <span style={{ fontSize: 11, fontWeight: 700, color: '#94a3b8', minWidth: 60 }}>{issue.id}</span>
                <span style={{ flex: 1, fontSize: 13, fontWeight: 600, color: '#1e293b' }}>{issue.title}</span>
                <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 20, background: '#f1f5f9', color: '#64748b', fontWeight: 600 }}>{issue.label}</span>
                <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 20, background: statusMeta.bg, color: statusMeta.color, fontWeight: 700 }}>{statusMeta.label}</span>
                <span style={{ fontSize: 11, color: '#94a3b8', minWidth: 36 }}>{issue.assignee[0]}</span>
              </div>
            )
          })
        )}
      </div>

      {/* Footer */}
      <div style={{ marginTop: 16, display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingTop: 12, borderTop: '1px solid #f1f5f9' }}>
        <span style={{ fontSize: 13, color: '#94a3b8' }}>{filtered.length}개 / {ISSUES_125.length}개 이슈</span>
        <SolidButton color="black" size="medium">
          <SolidButton.Center>이슈 추가</SolidButton.Center>
        </SolidButton>
      </div>
    </div>
  )
}

export const MUITailwind125IssueTracker: StoryObj = {
  name: 'MUI + Tailwind UI — 이슈 트래커 (Cycle 125)',
  parameters: {
    layout: 'centered',
    docs: {
      description: {
        story:
          'MUI + Tailwind UI 벤치마크 — Cycle 125. ' +
          'Drawer 필터 패널 + 레이블 ChipLink 필터 + TextField 검색 + 이슈 목록. ' +
          'SolidButton/OutlineButton 액션, LabelBadge 상태 표시를 결합한 이슈 트래커입니다.',
      },
    },
  },
  render: () => <IssueTracker125Render />,
}

/* ============================================================
   Cycle 126 Template: Chakra UI + Arco Design
   알림 센터 — Skeleton 로딩 + Toast 액션 피드백
   ============================================================ */
import { Toaster, toast } from '../components/Toast'

const NOTIFICATIONS_126 = [
  { id: 1, type: 'deploy', avatar: 'VR', name: 'Vercel', message: 'orbit-ui 프리뷰 배포 완료', time: '방금 전', read: false },
  { id: 2, type: 'mention', avatar: 'JK', name: '김준혁', message: '@hjunkim 이슈 #312를 리뷰해주세요', time: '3분 전', read: false },
  { id: 3, type: 'pr', avatar: 'SL', name: 'Sarah Lee', message: 'PR #148 Cycle 125 스토리 머지됨', time: '15분 전', read: true },
  { id: 4, type: 'ci', avatar: 'CI', name: 'GitHub Actions', message: 'pnpm test 전체 통과 ✓ 58/58', time: '1시간 전', read: true },
  { id: 5, type: 'comment', avatar: 'MJ', name: '박민정', message: 'Skeleton 컴포넌트에 댓글을 남겼습니다', time: '2시간 전', read: true },
]

const TYPE_COLORS_126: Record<string, string> = {
  deploy: '#7c3aed',
  mention: '#2563eb',
  pr: '#16a34a',
  ci: '#0891b2',
  comment: '#d97706',
}

function NotificationCenter126Render() {
  const [loading, setLoading] = React.useState(false)
  const [notifications, setNotifications] = React.useState(NOTIFICATIONS_126)
  const [filter, setFilter] = React.useState<'all' | 'unread'>('all')

  const shown = filter === 'unread' ? notifications.filter(n => !n.read) : notifications

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })))
    toast.success('모든 알림을 읽음으로 표시했습니다')
  }

  const dismiss = (id: number) => {
    setNotifications(prev => prev.filter(n => n.id !== id))
    toast.info('알림이 삭제되었습니다', {
      action: {
        label: '실행 취소',
        onClick: () => setNotifications(NOTIFICATIONS_126),
      },
    })
  }

  const refresh = async () => {
    setLoading(true)
    toast.loading('알림을 새로고침 중...', { id: 'refresh' })
    await new Promise(r => setTimeout(r, 1500))
    setNotifications(NOTIFICATIONS_126)
    setLoading(false)
    toast.success('알림을 새로고침했습니다', { id: 'refresh' })
  }

  return (
    <div style={{ width: 420, fontFamily: 'Inter, system-ui, sans-serif', display: 'flex', flexDirection: 'column', gap: 0 }}>
      <Toaster position="top-right" />
      {/* 헤더 */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '16px 20px', borderBottom: '1px solid #f1f5f9' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ fontSize: 16, fontWeight: 700, color: '#1e293b' }}>알림</span>
          <CounterBadge style={{ background: '#2563eb', color: '#fff' }}>{notifications.filter(n => !n.read).length}</CounterBadge>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          <OutlineButton color="black" size="small" onClick={markAllRead}>
            <OutlineButton.Center>모두 읽음</OutlineButton.Center>
          </OutlineButton>
          <SolidButton color="black" size="small" onClick={refresh}>
            <SolidButton.Center>새로고침</SolidButton.Center>
          </SolidButton>
        </div>
      </div>
      {/* 필터 탭 */}
      <div style={{ display: 'flex', borderBottom: '1px solid #f1f5f9', padding: '0 20px' }}>
        {(['all', 'unread'] as const).map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{
              padding: '10px 14px',
              fontSize: 13,
              fontWeight: filter === f ? 700 : 400,
              color: filter === f ? '#1e293b' : '#94a3b8',
              background: 'none',
              border: 'none',
              borderBottom: filter === f ? '2px solid #1e293b' : '2px solid transparent',
              cursor: 'pointer',
            }}
          >
            {f === 'all' ? '전체' : '읽지 않음'}
          </button>
        ))}
      </div>
      {/* 알림 목록 or 스켈레톤 */}
      <div style={{ display: 'flex', flexDirection: 'column' }}>
        {loading
          ? Array.from({ length: 4 }).map((_, i) => (
              <div key={i} style={{ display: 'flex', alignItems: 'flex-start', gap: 12, padding: '14px 20px', borderBottom: '1px solid #f8fafc' }}>
                <Skeleton height={36} width={36} style={{ borderRadius: '50%', flexShrink: 0 }} />
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 7 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                    <Skeleton height={12} width="45%" />
                    <Skeleton height={10} width={48} />
                  </div>
                  <Skeleton height={11} width="85%" />
                  <Skeleton height={10} width="60%" />
                </div>
              </div>
            ))
          : shown.map(n => (
              <div key={n.id} style={{
                display: 'flex', alignItems: 'flex-start', gap: 12, padding: '14px 20px',
                borderBottom: '1px solid #f8fafc',
                background: n.read ? 'transparent' : '#f0f9ff',
              }}>
                {/* 아바타 */}
                <div style={{
                  width: 36, height: 36, borderRadius: '50%', flexShrink: 0,
                  background: TYPE_COLORS_126[n.type] ?? '#94a3b8',
                  color: '#fff', fontSize: 11, fontWeight: 700,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                }}>
                  {n.avatar}
                </div>
                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 3 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ fontSize: 12, fontWeight: 600, color: '#1e293b' }}>{n.name}</span>
                    <span style={{ fontSize: 11, color: '#94a3b8' }}>{n.time}</span>
                  </div>
                  <span style={{ fontSize: 12, color: '#475569', lineHeight: 1.4 }}>{n.message}</span>
                  {!n.read && (
                    <span style={{ fontSize: 10, fontWeight: 600, color: '#2563eb', marginTop: 2 }}>● 새 알림</span>
                  )}
                </div>
                <button
                  onClick={() => dismiss(n.id)}
                  style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#cbd5e1', fontSize: 14, padding: 4, flexShrink: 0 }}
                >
                  ✕
                </button>
              </div>
            ))
        }
      </div>
      {/* 빈 상태 */}
      {!loading && shown.length === 0 && (
        <div style={{ padding: '40px 20px', textAlign: 'center', color: '#94a3b8', fontSize: 13 }}>
          읽지 않은 알림이 없습니다
        </div>
      )}
    </div>
  )
}

export const ChakraArco126NotificationCenter: StoryObj = {
  name: 'Chakra UI + Arco Design — 알림 센터 (Cycle 126)',
  parameters: {
    layout: 'centered',
    docs: {
      description: {
        story:
          'Chakra UI + Arco Design 벤치마크 — Cycle 126. ' +
          'Skeleton 로딩 플레이스홀더 + Toast 액션 피드백이 결합된 알림 센터 템플릿. ' +
          '새로고침 시 Skeleton → 실제 콘텐츠 전환, 삭제/읽음 처리에 Toast 피드백을 제공합니다.',
      },
    },
  },
  render: () => <NotificationCenter126Render />,
}

/* ============================================================
   Cycle 127 Template: shadcn/ui + Radix UI
   커맨드 팔레트 — Popover + TextArea 검색 + 액션 선택
   ============================================================ */
const CMD_ACTIONS = [
  { id: 'new-issue', label: '새 이슈 생성', category: '이슈', shortcut: '⌘N', icon: '＋' },
  { id: 'search-issue', label: '이슈 검색', category: '이슈', shortcut: '⌘F', icon: '🔍' },
  { id: 'new-pr', label: 'PR 생성', category: '코드', shortcut: '⌘P', icon: '⑃' },
  { id: 'switch-branch', label: '브랜치 전환', category: '코드', shortcut: '⌘B', icon: '⑂' },
  { id: 'open-settings', label: '설정 열기', category: '앱', shortcut: '⌘,', icon: '⚙' },
  { id: 'toggle-theme', label: '다크모드 전환', category: '앱', shortcut: '⌘⇧D', icon: '◑' },
  { id: 'open-docs', label: '문서 열기', category: '도움말', shortcut: '⌘?', icon: '📖' },
  { id: 'report-bug', label: '버그 리포트', category: '도움말', shortcut: '', icon: '🐛' },
]

function CommandPalette127Render() {
  const [open, setOpen] = useState(false)
  const [query, setQuery] = useState('')
  const [recent, setRecent] = useState<string[]>(['new-issue', 'switch-branch'])

  const filtered = query
    ? CMD_ACTIONS.filter(a => a.label.includes(query) || a.category.includes(query))
    : CMD_ACTIONS

  const categories = [...new Set(filtered.map(a => a.category))]

  const run = (id: string) => {
    setRecent(prev => [id, ...prev.filter(r => r !== id)].slice(0, 3))
    setOpen(false)
    setQuery('')
  }

  return (
    <div style={{ width: 480, fontFamily: 'Inter, system-ui, sans-serif', display: 'flex', flexDirection: 'column', gap: 16 }}>
      {/* 헤더 트리거 바 */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '12px 16px', background: '#f8fafc', borderRadius: 10, border: '1px solid #e2e8f0' }}>
        <span style={{ fontSize: 14, fontWeight: 700, color: '#1e293b' }}>orbit-ui</span>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <SolidButton color="black" size="small" onClick={() => setOpen(true)}>
            <SolidButton.Center>커맨드 팔레트 열기 ⌘K</SolidButton.Center>
          </SolidButton>
        </div>
      </div>

      {/* 커맨드 팔레트 (Popover 시뮬레이션) */}
      {open && (
        <div style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', zIndex: 50,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }} onClick={() => setOpen(false)}>
          <div
            style={{ width: 440, background: '#fff', borderRadius: 14, boxShadow: '0 20px 60px rgba(0,0,0,0.2)', overflow: 'hidden' }}
            onClick={(e) => e.stopPropagation()}
          >
            {/* 검색 입력 */}
            <div style={{ padding: '12px 16px', borderBottom: '1px solid #f1f5f9' }}>
              <input
                autoFocus
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="명령어 검색..."
                style={{ width: '100%', fontSize: 15, border: 'none', outline: 'none', color: '#1e293b', background: 'transparent', boxSizing: 'border-box' }}
              />
            </div>
            {/* 최근 사용 */}
            {!query && recent.length > 0 && (
              <div style={{ padding: '8px 0' }}>
                <div style={{ padding: '4px 16px', fontSize: 11, fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.06em' }}>최근 사용</div>
                {recent.map(id => {
                  const a = CMD_ACTIONS.find(x => x.id === id)
                  if (!a) return null
                  return (
                    <button
                      key={a.id}
                      onClick={() => run(a.id)}
                      style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '8px 16px', background: 'none', border: 'none', cursor: 'pointer', textAlign: 'left' }}
                      onMouseEnter={(e) => { e.currentTarget.style.background = '#f8fafc' }}
                      onMouseLeave={(e) => { e.currentTarget.style.background = 'none' }}
                    >
                      <span style={{ fontSize: 15, width: 20, textAlign: 'center' }}>{a.icon}</span>
                      <span style={{ flex: 1, fontSize: 13, color: '#1e293b' }}>{a.label}</span>
                      {a.shortcut && <span style={{ fontSize: 11, color: '#94a3b8', background: '#f1f5f9', padding: '2px 6px', borderRadius: 4 }}>{a.shortcut}</span>}
                    </button>
                  )
                })}
              </div>
            )}
            {/* 카테고리별 액션 */}
            <div style={{ maxHeight: 280, overflowY: 'auto', padding: '4px 0' }}>
              {categories.map(cat => (
                <div key={cat}>
                  <div style={{ padding: '6px 16px 2px', fontSize: 11, fontWeight: 700, color: '#94a3b8', textTransform: 'uppercase', letterSpacing: '0.06em' }}>{cat}</div>
                  {filtered.filter(a => a.category === cat).map(a => (
                    <button
                      key={a.id}
                      onClick={() => run(a.id)}
                      style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '8px 16px', background: 'none', border: 'none', cursor: 'pointer', textAlign: 'left' }}
                      onMouseEnter={(e) => { e.currentTarget.style.background = '#f8fafc' }}
                      onMouseLeave={(e) => { e.currentTarget.style.background = 'none' }}
                    >
                      <span style={{ fontSize: 15, width: 20, textAlign: 'center' }}>{a.icon}</span>
                      <span style={{ flex: 1, fontSize: 13, color: '#1e293b' }}>{a.label}</span>
                      {a.shortcut && <span style={{ fontSize: 11, color: '#94a3b8', background: '#f1f5f9', padding: '2px 6px', borderRadius: 4 }}>{a.shortcut}</span>}
                    </button>
                  ))}
                </div>
              ))}
              {filtered.length === 0 && (
                <div style={{ padding: '24px', textAlign: 'center', color: '#94a3b8', fontSize: 13 }}>
                  &quot;{query}&quot;에 대한 결과 없음
                </div>
              )}
            </div>
            <div style={{ padding: '8px 16px', borderTop: '1px solid #f1f5f9', display: 'flex', gap: 12, fontSize: 11, color: '#94a3b8' }}>
              <span>↑↓ 이동</span>
              <span>↵ 실행</span>
              <span>ESC 닫기</span>
            </div>
          </div>
        </div>
      )}

      {/* 최근 실행 이력 */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        <div style={{ fontSize: 13, fontWeight: 700, color: '#1e293b' }}>최근 실행 명령어</div>
        {recent.length === 0 ? (
          <div style={{ fontSize: 13, color: '#94a3b8' }}>없음 — 커맨드 팔레트를 열어 실행해보세요</div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
            {recent.map(id => {
              const a = CMD_ACTIONS.find(x => x.id === id)
              if (!a) return null
              return (
                <div key={id} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '8px 12px', background: '#f8fafc', borderRadius: 8, border: '1px solid #f1f5f9' }}>
                  <span>{a.icon}</span>
                  <span style={{ fontSize: 13, color: '#1e293b', flex: 1 }}>{a.label}</span>
                  <LabelBadge style={{ fontSize: 10 }}>{a.category}</LabelBadge>
                </div>
              )
            })}
          </div>
        )}
      </div>

      {/* 노트 입력 (TextArea 활용) */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
        <div style={{ fontSize: 13, fontWeight: 700, color: '#1e293b' }}>빠른 메모</div>
        <TextField placeholder="이슈 번호, PR 링크 등 메모..." />
      </div>
    </div>
  )
}

